    web->index.html.code
    <!DOCTYPE html>
    <html>
    <head>
        <title>SoT Multi-Room Chat</title>
        <style>
            body { font-family: 'Inter', sans-serif; background: #0f172a; color: white; display: flex; height: 100vh; margin: 0; }
            #sidebar { width: 260px; background: #1e293b; border-right: 1px solid #334155; display: flex; flex-direction: column; padding: 20px; }
            #main { flex: 1; display: flex; flex-direction: column; }
            #messages { flex: 1; overflow-y: auto; padding: 20px; list-style: none; }
            #messages li { margin-bottom: 10px; padding: 10px; background: #1e293b; border-radius: 8px; border-left: 4px solid #38bdf8; }
            #messages li b { color: #38bdf8; margin-right: 10px; }
            #form { display: flex; padding: 20px; background: #1e293b; gap: 10px; }
            input { flex: 1; padding: 12px; border-radius: 6px; border: 1px solid #334155; background: #0f172a; color: white; outline: none; }
            button { padding: 12px 24px; background: #38bdf8; color: #0f172a; border: none; border-radius: 6px; font-weight: bold; cursor: pointer; }
            .room-item { padding: 10px; margin-bottom: 5px; background: #0f172a; border-radius: 6px; cursor: pointer; transition: 0.2s; border: 1px solid transparent; }
            .room-item:hover { background: #334155; }
            .room-item.active { border-color: #38bdf8; background: #1e293b; }
            #login { position: fixed; inset: 0; background: #0f172a; display: flex; align-items: center; justify-content: center; z-index: 100; }
            .login-box { background: #1e293b; padding: 40px; border-radius: 12px; text-align: center; border: 1px solid #334155; }
        </style>
    </head>
    <body>
        <div id="login">
            <div class="login-box">
                <h2>Join Chat Room</h2>
                <input type="text" id="username" placeholder="Enter your username...">
                <button onclick="join()">Join</button>
            </div>
        </div>

        <div id="sidebar">
            <h3>Rooms</h3>
            <div id="room-list"></div>
            <div style="margin-top: auto; padding-top: 20px;">
                <input type="text" id="new-room-name" placeholder="New room...">
                <button onclick="createRoom()" style="width: 100%; margin-top: 10px;">Create Room</button>
            </div>
        </div>

        <div id="main">
            <div id="header" style="padding: 15px 20px; border-bottom: 1px solid #334155; background: #1e293b;">
                <h3 id="current-room-title" style="margin:0">Room: General</h3>
            </div>
            <ul id="messages"></ul>
            <div id="form">
                <input type="text" id="input" placeholder="Type a message...">
                <button onclick="send()">Send</button>
            </div>
        </div>

        <script src="/socket.io/socket.io.js"></script>
        <script>
            const socket = io();
            let currentRoom = "General";
            const messages = document.getElementById('messages');
            const input = document.getElementById('input');
            const roomListEl = document.getElementById('room-list');
            const currentRoomTitle = document.getElementById('current-room-title');

            function join() {
                const name = document.getElementById('username').value.trim();
                if (name) {
                    socket.emit('join', name);
                    document.getElementById('login').style.display = 'none';
                }
            }

            function createRoom() {
                const name = document.getElementById('new-room-name').value.trim();
                if (name) {
                    socket.emit('createRoom', name);
                    document.getElementById('new-room-name').value = '';
                }
            }

            function switchRoom(room) {
                currentRoom = room;
                socket.emit('joinRoom', room);
                currentRoomTitle.innerText = `Room: ${room}`;
                messages.innerHTML = ''; // Clear for new room
                updateRoomUI();
            }

            function updateRoomUI() {
                document.querySelectorAll('.room-item').forEach(el => {
                    el.classList.toggle('active', el.innerText === currentRoom);
                });
            }

            function send() {
                const text = input.value.trim();
                if (text) {
                    socket.emit('chatMessage', { text, room: currentRoom });
                    input.value = '';
                }
            }

            socket.on('roomList', (rooms) => {
                roomListEl.innerHTML = '';
                rooms.forEach(room => {
                    const el = document.createElement('div');
                    el.className = `room-item ${room === currentRoom ? 'active' : ''}`;
                    el.innerText = room;
                    el.onclick = () => switchRoom(room);
                    roomListEl.appendChild(el);
                });
            });

            socket.on('message', (msg) => {
                const item = document.createElement('li');
                item.innerHTML = `<b>${msg.user}</b> ${msg.text}`;
                messages.appendChild(item);
                messages.scrollTop = messages.scrollHeight;
            });

            input.addEventListener('keypress', (e) => { if (e.key === 'Enter') send(); });
        </script>
    </body>
    </html>
    web->index.html.end

chat/chat_engine.rawSource:
graph TD
    extern->socketio from "socket.io"

    ChatManager[ChatManager.ts{io: any, users: Map<string, string>, rooms: Set<string>}]
    
    @ChatManager.constructor
    @@ChatManager.constructor.code
        this.users = new Map();
        this.rooms = new Set(["General"]);
    @@ChatManager.constructor.end

    @ChatManager.attach{server: any}: void
    @@ChatManager.attach.code
        this.io = new socketio.Server(server);
        
        this.io.on("connection", (socket) => {
            console.log("рҹ”Ң User connected:", socket.id);

            socket.on("join", (username) => {
                this.users.set(socket.id, username);
                socket.join("General");
                this.io.to("General").emit("message", {
                    user: "System",
                    text: `${username} joined General`
                });
                socket.emit("roomList", Array.from(this.rooms));
            });

            socket.on("createRoom", (roomName) => {
                if (roomName && !this.rooms.has(roomName)) {
                    this.rooms.add(roomName);
                    this.io.emit("roomList", Array.from(this.rooms));
                }
            });

            socket.on("joinRoom", (roomName) => {
                const username = this.users.get(socket.id) || "Anonymous";
                if (this.rooms.has(roomName)) {
                    // Leave previous rooms
                    socket.rooms.forEach(r => { if(r !== socket.id) socket.leave(r); });
                    socket.join(roomName);
                    socket.emit("message", { user: "System", text: `You joined ${roomName}` });
                    socket.to(roomName).emit("message", { user: "System", text: `${username} joined ${roomName}` });
                }
            });

            socket.on("chatMessage", (data) => {
                const username = this.users.get(socket.id) || "Anonymous";
                const room = Array.from(socket.rooms).find(r => r !== socket.id) || "General"; // Get current room
                this.io.to(room).emit("message", {
                    user: username,
                    text: data.text
                });
            });

            socket.on("disconnect", () => {
                const username = this.users.get(socket.id);
                // System message to all rooms they were in
                this.users.delete(socket.id);
            });
        });
    @@ChatManager.end

