        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
      }

      .controls {
          display: flex;
          gap: 20px;
          margin-bottom: 30px;
          width: 100%;
          justify-content: center;
      }

      .search-box {
          background: var(--glass);
          border: 1px solid var(--glass-border);
          padding: 12px 20px;
          border-radius: 100px;
          color: white;
          width: 400px;
          font-family: inherit;
          font-size: 16px;
          backdrop-filter: blur(10px);
          transition: all 0.3s ease;
      }

      .search-box:focus {
          outline: none;
          background: rgba(255, 255, 255, 0.08);
          border-color: rgba(255, 255, 255, 0.3);
          box-shadow: 0 0 20px rgba(255, 255, 255, 0.05);
      }

      .periodic-table {
        display: grid;
        grid-template-columns: repeat(18, 1fr);
        grid-template-rows: repeat(10, 1fr);
        gap: 6px;
        padding: 10px;
        position: relative;
      }

      .element-card {
        aspect-ratio: 1;
        width: 65px;
        position: relative;
        cursor: pointer;
        display: flex;
        flex-direction: column;
        justify-content: center;
        align-items: center;
        border-radius: 8px;
        transition: all 0.4s cubic-bezier(0.23, 1, 0.32, 1);
        border: 1px solid rgba(255, 255, 255, 0.05);
        text-align: center;
        background: var(--glass);
        backdrop-filter: blur(4px);
      }

      .element-card:hover {
        transform: scale(1.4) translateY(-5px);
        z-index: 100;
        border-color: rgba(255, 255, 255, 0.4);
        box-shadow: 0 10px 30px rgba(0,0,0,0.5);
      }

      .element-card.dimmed {
          opacity: 0.15;
          filter: grayscale(0.8) blur(1px);
          transform: scale(0.95);
      }

      .element-card.highlight {
          transform: scale(1.1);
          border-color: white;
          box-shadow: 0 0 20px rgba(255, 255, 255, 0.2);
          z-index: 50;
      }

      .element-number {
        position: absolute;
        top: 4px;
        left: 6px;
        font-size: 9px;
        font-weight: 600;
        opacity: 0.5;
      }

      .element-symbol {
        font-size: 22px;
        font-weight: 800;
        letter-spacing: -0.5px;
      }

      .element-name {
        font-size: 8px;
        font-weight: 400;
        margin-top: 2px;
        opacity: 0.7;
        text-transform: uppercase;
        letter-spacing: 0.5px;
      }

      .legend {
        display: flex;
        flex-wrap: wrap;
        gap: 12px;
        justify-content: center;
        margin-top: 50px;
        max-width: 1100px;
        background: var(--glass);
        padding: 20px;
        border-radius: 20px;
        border: 1px solid var(--glass-border);
        backdrop-filter: blur(10px);
      }
      
      .legend-item {
        display: flex;
        align-items: center;
        gap: 8px;
        font-size: 13px;
        font-weight: 500;
        padding: 6px 12px;
        border-radius: 100px;
        cursor: pointer;
        transition: all 0.2s ease;
        border: 1px solid transparent;
      }

      .legend-item:hover {
          background: rgba(255, 255, 255, 0.05);
          border-color: var(--glass-border);
      }

      .legend-item.active {
          background: rgba(255, 255, 255, 0.1);
          border-color: rgba(255, 255, 255, 0.3);
      }

      .legend-color {
        width: 12px;
        height: 12px;
        border-radius: 3px;
      }
      
      #modal {
          display: none;
          position: fixed;
          top: 50%;
          left: 50%;
          transform: translate(-50%, -50%) scale(0.9);
          background: rgba(10, 15, 25, 0.95);
          padding: 40px;
          border-radius: 32px;
          box-shadow: 0 30px 100px rgba(0,0,0,0.8);
          z-index: 1000;
          width: 450px;
          border: 1px solid rgba(255,255,255,0.15);
          backdrop-filter: blur(20px);
          transition: all 0.4s cubic-bezier(0.23, 1, 0.32, 1);
          opacity: 0;
      }

      #modal.show {
          transform: translate(-50%, -50%) scale(1);
          opacity: 1;
      }
      
      #modal h2 { margin: 0; font-size: 80px; font-weight: 800; line-height: 1;}
      #modal .name { font-size: 28px; font-weight: 600; margin: 10px 0 30px 0; letter-spacing: -0.5px;}
      
      .data-grid {
          display: grid;
          grid-template-columns: 1fr 1fr;
