    </style>
  </head>
  <body>
    <div class="header">
        <h1>Periodic Table</h1>
        <div class="controls">
            <input type="text" class="search-box" id="search" placeholder="Search by name, symbol, or atomic number..." spellcheck="false">
        </div>
    </div>
    
    <div class="periodic-table" id="ptable"></div>
    
    <div class="legend" id="legend"></div>
    
    <div id="overlay" onclick="closeModal()"></div>
    <div id="modal">
        <div class="close-btn" onclick="closeModal()">вң•</div>
        <h2 id="m-symbol"></h2>
        <div class="name" id="m-name"></div>
        
        <div class="data-grid">
            <div class="data-item">
                <div class="data-label">Atomic Number</div>
                <div class="data-value" id="m-number"></div>
            </div>
            <div class="data-item">
                <div class="data-label">Atomic Mass</div>
                <div class="data-value" id="m-mass"></div>
            </div>
            <div class="data-item" style="grid-column: span 2;">
                <div class="data-label">Category</div>
                <div class="data-value" id="m-cat"></div>
            </div>
            <div class="data-item">
                <div class="data-label">Discovery Year</div>
                <div class="data-value" id="m-year"></div>
            </div>
            <div class="data-item">
                <div class="data-label">Discovered By</div>
                <div class="data-value" id="m-by"></div>
            </div>
        </div>
    </div>

    <script>
      let elementsData = [];
      let activeCategory = null;

      const categories = [
        'diatomic-nonmetal', 'noble-gas', 'alkali-metal', 'alkaline-earth-metal',
        'metalloid', 'polyatomic-nonmetal', 'post-transition-metal', 'transition-metal',
        'lanthanide', 'actinide', 'halogen'
      ];
      
      function getCategoryColor(cat) {
        return `var(--${cat})`;
      }

      function initLegend() {
          const leg = document.getElementById('legend');
          categories.forEach(cat => {
              const div = document.createElement('div');
              div.className = 'legend-item';
              div.innerHTML = `<div class="legend-color" style="background: ${getCategoryColor(cat)}"></div> ${cat.replace(/-/g, ' ')}`;
              div.onclick = () => toggleCategory(cat, div);
              leg.appendChild(div);
          });
      }

      function toggleCategory(cat, el) {
          if (activeCategory === cat) {
              activeCategory = null;
              document.querySelectorAll('.legend-item').forEach(li => li.classList.remove('active'));
          } else {
              activeCategory = cat;
              document.querySelectorAll('.legend-item').forEach(li => li.classList.remove('active'));
              el.classList.add('active');
          }
          filterElements();
      }

      async function fetchData() {
        const res = await fetch('/api/elements');
        elementsData = await res.json();
        renderTable(elementsData);
      }

      function renderTable(data) {
        const table = document.getElementById('ptable');
        table.innerHTML = '';
        
        data.forEach(el => {
          const card = document.createElement('div');
          card.className = 'element-card';
          card.id = `el-${el.number}`;
          
          let col = el.group;
          let row = el.period;
          
          if (el.category === 'lanthanide') {
            row = 9;
            col = el.number - 57 + 4;
          } else if (el.category === 'actinide') {
            row = 10;
            col = el.number - 89 + 4;
          }
          
          card.style.gridColumn = col;
          card.style.gridRow = row;
          card.style.borderLeft = `4px solid ${getCategoryColor(el.category)}`;
          
          card.innerHTML = `
            <div class="element-number">${el.number}</div>
            <div class="element-symbol" style="color: ${getCategoryColor(el.category)}">${el.symbol}</div>
            <div class="element-name">${el.name}</div>
          `;
          
          card.onclick = () => openModal(el);
          table.appendChild(card);
        });
      }

      function filterElements() {
          const query = document.getElementById('search').value.toLowerCase();
          
          elementsData.forEach(el => {
              const card = document.getElementById(`el-${el.number}`);
              if (!card) return;

              const matchesSearch = el.name.toLowerCase().includes(query) || 
                                   el.symbol.toLowerCase().includes(query) || 
                                   el.number.toString().includes(query);
              
              const matchesCategory = !activeCategory || el.category === activeCategory;

              if (matchesSearch && matchesCategory) {
                  card.classList.remove('dimmed');
                  if (query.length > 0 || activeCategory) {
                      card.classList.add('highlight');
                  } else {
                      card.classList.remove('highlight');
                  }
              } else {
                  card.classList.add('dimmed');
                  card.classList.remove('highlight');
              }
          });
      }
      
      function openModal(el) {
          document.getElementById('m-symbol').innerText = el.symbol;
          document.getElementById('m-symbol').style.color = getCategoryColor(el.category);
          document.getElementById('m-name').innerText = el.name;
          document.getElementById('m-number').innerText = el.number;
          document.getElementById('m-mass').innerText = el.mass;
          document.getElementById('m-cat').innerText = el.category.replace(/-/g, ' ');
          document.getElementById('m-year').innerText = el.year || 'Unknown';
          document.getElementById('m-by').innerText = el.discoveredBy || 'N/A';
          
          const overlay = document.getElementById('overlay');
          const modal = document.getElementById('modal');
          
          modal.style.display = 'block';
          overlay.style.display = 'block';
          setTimeout(() => {
              overlay.classList.add('show');
              modal.classList.add('show');
          }, 10);
      }
      
      function closeModal() {
          const overlay = document.getElementById('overlay');
          const modal = document.getElementById('modal');
          
          overlay.classList.remove('show');
          modal.classList.remove('show');
          setTimeout(() => {
              overlay.style.display = 'none';
          }, 300);
      }

      document.getElementById('search').addEventListener('input', filterElements);

      initLegend();
      fetchData();
    </script>
  </body>
  </html>
  web->index.html.end

