graph TD
  %% ---- Entities ----
  Ship[Ship.ts{name: string, fuel: number, location: Planet, cargo: string[]}]
  Planet[Planet.ts{name: string, x: number, y: number, resource: string}]
  Trader[Trader.ts{name: string, credits: number, ship: Ship}]

  %% ---- Relationships ----
  Ship --> Planet
  Trader --> Ship

  type->TradeResult{success: boolean, message: string}

  %% ---- Ship Logic ----
  @Ship.calculateDistance{target: Planet}: number
  @@Ship.calculateDistance.code
    const dx = target.x - this.location.x;
    const dy = target.y - this.location.y;
    return Math.sqrt(dx * dx + dy * dy);
  @@Ship.calculateDistance.end

  @Ship.flyTo{target: Planet}: boolean
  @@Ship.flyTo.code
    const dist = this.calculateDistance(target);
    const fuelCost = Math.floor(dist * 2);
    if (this.fuel < fuelCost) {
      console.log(this.name + " doesn't have enough fuel to reach " + target.name + "!");
      return false;
    }
    this.fuel -= fuelCost;
    this.location = target;
    console.log(this.name + " arrived at " + target.name + ". Fuel remaining: " + this.fuel);
    return true;
  @@Ship.flyTo.end

  %% ---- Planet Logic ----
  @Planet.getPrice{item: string}: number
  @@Planet.getPrice.code
    // Dynamic pricing based on planet name length and item
    let base = this.name.length * 10;
    if (item === this.resource) return Math.floor(base * 0.5); // Cheap if they produce it
    return Math.floor(base * 1.5); // Expensive otherwise
  @@Planet.getPrice.end

  %% ---- Trader Logic ----
  @Trader.buyResource{planet: Planet, item: string}: boolean
  @@Trader.buyResource.code
    const price = planet.getPrice(item);
    if (this.credits < price) {
      console.log(this.name + " cannot afford " + item + " (" + price + " credits)");
      return false;
    }
    this.credits -= price;
    this.ship.cargo.push(item);
    console.log(this.name + " bought " + item + " for " + price + " credits.");
    return true;
  @@Trader.buyResource.end

  @Trader.sellResource{planet: Planet, item: string}: boolean
  @@Trader.sellResource.code
    const index = this.ship.cargo.indexOf(item);
    if (index === -1) {
       console.log(this.name + " doesn't have any " + item + " to sell!");
       return false;
    }
    const price = planet.getPrice(item) + 20; // Slight markup for selling
    this.credits += price;
    this.ship.cargo.splice(index, 1);
    console.log(this.name + " sold " + item + " for " + price + " credits. Total credits: " + this.credits);
    return true;
  @@Trader.sellResource.end

  %% ---- Main Simulation ----
  @@main.code
  async function runSpaceTradeSim() {
    console.log("=== Galactic Trade Empire Simulation ===");

    const earth = new Planet();
    earth.name = "Earth";
    earth.x = 0;
    earth.y = 0;
    earth.resource = "Water";

    const mars = new Planet();
    mars.name = "Mars";
    mars.x = 10;
    mars.y = 5;
    mars.resource = "Iron";

    const belarusP6 = new Planet();
    belarusP6.name = "Belarus P6";
    belarusP6.x = -15;
    belarusP6.y = 20;
    belarusP6.resource = "Crystals";

    const ship = new Ship();
    ship.name = "SS Antigravity";
    ship.fuel = 100;
    ship.location = earth;
    ship.cargo = [];

    const player = new Trader();
    player.name = "Commander Fishy";
    player.credits = 500;
    player.ship = ship;

    console.log("Welcome, " + player.name + "! Current Credits: " + player.credits);
    console.log("Starting at Earth. Looking for Iron...");

    // Trade Loop
    if (player.buyResource(earth, "Water")) {
      console.log("Heading to Mars to sell Water and buy Iron...");
      if (ship.flyTo(mars)) {
        player.sellResource(mars, "Water");
        player.buyResource(mars, "Iron");
        
        console.log("Heading to Belarus P6 to sell Iron...");
        if (ship.flyTo(belarusP6)) {
          player.sellResource(belarusP6, "Iron");
          player.buyResource(belarusP6, "Crystals");
        }
      }
    }

    console.log("\nSimulation Ended.");
    console.log("Final Report for " + player.name + ":");
    console.log("- Credits: " + player.credits);
    console.log("- Cargo: " + (ship.cargo.length ? ship.cargo.join(", ") : "Empty"));
    console.log("- Location: " + ship.location.name);
  }

  runSpaceTradeSim();
  @@main.end

minecraft/minecraft.rawSource:
extern->three from "three"
extern->SimplexNoise from "simplex-noise"
cliscripts->start npx -y http-server -p 8080
cliscripts->build tsc main.ts --outDir dist --skipLibCheck

// --- Types ---
type->ChunkKey = string

// --- Chunk Class ---
Chunk[Chunk.ts{group: any, meshes: any, x: number, z: number, matrix: any, maxInstances: number, voxels: Set}]
@Chunk.constructor{x: number, z: number, noise2D: any, materials: any}
@@Chunk.constructor.code
  this.x = x;
  this.z = z;
  this.matrix = new three.Matrix4();
  this.voxels = new Set();
  
  const size = 16;
  const heightLimit = 32;
  const geometry = new three.BoxGeometry(1, 1, 1);
  
  this.maxInstances = size * size * heightLimit;
  this.group = new three.Group();
  this.meshes = {};
  
  for (const key in materials) {
    this.meshes[key] = new three.InstancedMesh(geometry, materials[key], this.maxInstances);
    this.meshes[key].instanceMatrix.setUsage(three.DynamicDrawUsage);
    this.meshes[key].count = 0;
    this.meshes[key].frustumCulled = false;
    // Add custom property to identify the type when raycasting
    this.meshes[key].userData = { type: key, chunk: this };
    this.group.add(this.meshes[key]);
  }
  
  const seaLevel = 12;
  
  for (let lx = 0; lx < size; lx++) {
    for (let lz = 0; lz < size; lz++) {
      const gx = this.x * size + lx;
      const gz = this.z * size + lz;
      
      const baseEl = noise2D(gx / 128, gz / 128) * 10 + 10;
      const macroHills = noise2D(gx / 64, gz / 64) * 5;
      const detail = noise2D(gx / 16, gz / 16) * 2;
      
      const h = Math.max(1, Math.floor(baseEl + macroHills + detail));
      
      for (let ly = 0; ly < h && ly < heightLimit; ly++) {
        this.matrix.setPosition(lx, ly, lz);
        let type = 'stone';
        if (ly === h - 1) type = 'grass';
        else if (ly >= h - 3) type = 'dirt';
        
        const mesh = this.meshes[type];
        mesh.setMatrixAt(mesh.count++, this.matrix);
        this.voxels.add(lx + "," + ly + "," + lz);
      }
      
      // Water
      if (h < seaLevel) {
        for (let ly = h; ly < seaLevel && ly < heightLimit; ly++) {
          this.matrix.setPosition(lx, ly, lz);
          const mesh = this.meshes['water'];
          mesh.setMatrixAt(mesh.count++, this.matrix);
        }
      } else if (h >= seaLevel && h < heightLimit) {
        // Trees
        const isGrass = Math.floor(baseEl + macroHills + detail) === h;
        if (isGrass && h + 5 < heightLimit) {
          const treeChance = (Math.sin(gx * 12.9898 + gz * 78.233) * 43758.5453) % 1;
          if (Math.abs(treeChance) > 0.98) {
             const trunkHeight = Math.floor(Math.abs(Math.sin(gx * 7.123 + gz * 12.989) * 4)) + 3;
             for(let ty = 0; ty < trunkHeight; ty++) {
                this.matrix.setPosition(lx, h + ty, lz);
                const mesh = this.meshes['wood'];
                mesh.setMatrixAt(mesh.count++, this.matrix);
                this.voxels.add(lx + "," + (h + ty) + "," + lz);
             }
             for(let dx = -1; dx <= 1; dx++) {
               for(let dz = -1; dz <= 1; dz++) {
                 for(let dy = 0; dy <= 1; dy++) {
                   const leafX = lx + dx;
                   const leafZ = lz + dz;
                   if (leafX >= 0 && leafX < size && leafZ >= 0 && leafZ < size) {
                     if (!(dx === 0 && dz === 0 && dy === 0)) {
                       const leafY = h + trunkHeight - 1 + dy;
                       this.matrix.setPosition(leafX, leafY, leafZ);
                       const mesh = this.meshes['leaves'];
                       mesh.setMatrixAt(mesh.count++, this.matrix);
                       this.voxels.add(leafX + "," + leafY + "," + leafZ);
                     }
                   }
                 }
               }
             }
          }
        }
      }
    }
  }
  
  for (const key in this.meshes) {
    this.meshes[key].instanceMatrix.needsUpdate = true;
  }
  this.group.position.set(this.x * size, 0, this.z * size);
@@Chunk.constructor.end

// --- World Manager ---
World[World.ts{scene: any, chunks: Map, noise2D: any, renderDistance: number, materials: any}]
World --> Chunk

@World.constructor{scene: any, materials: any}
@@World.constructor.code
  this.scene = scene;
  this.chunks = new Map();
  this.noise2D = SimplexNoise.createNoise2D();
  this.renderDistance = 2;
  this.materials = materials;
@@World.constructor.end

@World.isSolid{x: number, y: number, z: number}: boolean
@@World.isSolid.code
  if (y < 0) return true; // Bedrock barrier
  
  // Need to duplicate the new multi-octave noise function here to keep collision accurate
  const baseEl = this.noise2D(x / 128, z / 128) * 10 + 10;
  const macroHills = this.noise2D(x / 64, z / 64) * 5;
  const detail = this.noise2D(x / 16, z / 16) * 2;
  const terrainHeight = Math.max(1, Math.floor(baseEl + macroHills + detail));
  
  if (y < terrainHeight) return true; // Inside natural generated terrain

  const cx = Math.floor(x / 16);
  const cz = Math.floor(z / 16);
  const chunk = this.chunks.get(cx + "," + cz);
  if (chunk) {
    const lx = Math.floor(x - cx * 16);
    const ly = Math.floor(y);
    const lz = Math.floor(z - cz * 16);
    return chunk.voxels.has(lx + "," + ly + "," + lz);
  }
  return false;
@@World.isSolid.end

@World.update{playerPos: any}: void
@@World.update.code
  const size = 16;
  const pX = Math.floor(playerPos.x / size);
  const pZ = Math.floor(playerPos.z / size);

  for (let x = pX - this.renderDistance; x <= pX + this.renderDistance; x++) {
    for (let z = pZ - this.renderDistance; z <= pZ + this.renderDistance; z++) {
      const key = x + "," + z;
      if (!this.chunks.has(key)) {
        const chunk = new Chunk(x, z, this.noise2D, this.materials);
        this.chunks.set(key, chunk);
        this.scene.add(chunk.group);
      }
    }
  }
  
  const unloadDist = this.renderDistance + 1;
  for (const [key, chunk] of this.chunks) {
    const dx = chunk.x - pX;
    const dz = chunk.z - pZ;
    if (Math.abs(dx) > unloadDist || Math.abs(dz) > unloadDist) {
      this.scene.remove(chunk.group);
      for (const t in chunk.meshes) { chunk.meshes[t].dispose(); }
      this.chunks.delete(key);
    }
  }
@@World.update.end

// --- Player Controller ---
Player[Player.ts{camera: any, keys: any, velocity: any, height: number, radius: number, raycaster: any, torch: any, selectedBlock: number}]
@Player.constructor{camera: any, scene: any}
@@Player.constructor.code
  this.camera = camera;
  this.keys = {};
  this.velocity = new three.Vector3(0, 0, 0);
  this.height = 1.7; 
  this.radius = 0.3; 
  this.raycaster = new three.Raycaster();
  this.raycaster.far = 10;
  this.selectedBlock = 0;
  
  // Dynamic torch light
  this.torch = new three.PointLight(0xfff0dd, 1, 15);
  scene.add(this.torch);
  
  window.addEventListener('keydown', (e) => {
    this.keys[e.code] = true;
    if (e.code.startsWith('Digit')) {
      const num = parseInt(e.code.replace('Digit', ''));
      if (num >= 1 && num <= 6) {
        this.selectedBlock = num - 1;
        // Update UI highlight
        document.querySelectorAll('.slot').forEach((s, i) => {
          s.classList.toggle('active', i === this.selectedBlock);
        });
      }
    }
  });
  window.addEventListener('keyup', (e) => this.keys[e.code] = false);
  window.addEventListener('mousemove', (e) => {
    if (document.pointerLockElement) {
      this.camera.rotation.y -= e.movementX * 0.002;
      this.camera.rotation.x -= e.movementY * 0.002;
      this.camera.rotation.x = Math.max(-1.5, Math.min(1.5, this.camera.rotation.x));
    }
  });
@@Player.constructor.end

@Player.update{delta: number, world: any}: void
@@Player.update.code
  let moveSpeed = (this.keys['ShiftLeft'] ? 15 : 8) * delta;
  let gravity = 28 * delta;
  
  const feetY = this.camera.position.y - this.height;
  const seaLevel = 12;
  const inWater = feetY < seaLevel && 
                  !world.isSolid(this.camera.position.x, feetY, this.camera.position.z);

  if (inWater) {
    moveSpeed *= 0.6; // Slower in water
    gravity = 5 * delta; // Less gravity (buoyancy)
    this.velocity.y *= 0.9; // Water drag
    
    if (this.keys['Space']) {
      this.velocity.y += 18 * delta; // Swim upwards
    }
  }
  
  this.torch.position.copy(this.camera.position);

  // 1. Vertical Physics

  this.velocity.y -= gravity;
  let nextY = this.camera.position.y + this.velocity.y * delta;
  
  // Head collision (ceiling check)
  if (world.isSolid(this.camera.position.x, nextY + 0.1, this.camera.position.z) && this.velocity.y > 0) {
    this.velocity.y = 0;
  }
  
  if (world.isSolid(this.camera.position.x, nextY - this.height, this.camera.position.z)) {
    this.velocity.y = 0;
    nextY = Math.ceil(nextY - this.height) + this.height;
    if (this.keys['Space'] && !inWater) this.velocity.y = 12; // Increased jump power from 10 to 12
  }
  this.camera.position.y = nextY;
  
  // Fall respawn
  if (this.camera.position.y < -50) {
    this.camera.position.set(8, 20, 8);
    this.velocity.set(0, 0, 0);
  }

  // 2. Horizontal Movement + Collision
  const moveDir = new three.Vector3();
  if (this.keys['KeyW']) moveDir.z -= 1;
  if (this.keys['KeyS']) moveDir.z += 1;
  if (this.keys['KeyA']) moveDir.x -= 1;
  if (this.keys['KeyD']) moveDir.x += 1;
  
  moveDir.normalize().applyQuaternion(this.camera.quaternion);
  moveDir.y = 0; 
  moveDir.multiplyScalar(moveSpeed);

  // X Collision (check feet and head level)
  const xNext = this.camera.position.x + moveDir.x + (Math.sign(moveDir.x) * this.radius);
  const blockedX = world.isSolid(xNext, this.camera.position.y - 1.0, this.camera.position.z) || 
                   world.isSolid(xNext, this.camera.position.y - 0.3, this.camera.position.z);
  if (!blockedX) {
    this.camera.position.x += moveDir.x;
  }
  
  // Z Collision (check feet and head level)
  const zNext = this.camera.position.z + moveDir.z + (Math.sign(moveDir.z) * this.radius);
  const blockedZ = world.isSolid(this.camera.position.x, this.camera.position.y - 1.0, zNext) || 
                   world.isSolid(this.camera.position.x, this.camera.position.y - 0.3, zNext);
  if (!blockedZ) {
    this.camera.position.z += moveDir.z;
  }
  
  // Water auto-step (clamber out of water onto a shore/block)
  if (inWater && (blockedX || blockedZ) && this.keys['Space']) {
    this.velocity.y = 8;
  }
@@Player.update.end

// --- Clouds Layer ---
Clouds[Clouds.ts{scene: any, mesh: any, maxDisplacement: number, time: number}]
@Clouds.constructor{scene: any}
@@Clouds.constructor.code
  this.scene = scene;
  this.time = 0;
  
  const size = 64; // Grid size for clouds (64x64 blocks)
  const spread = 8; // Distance between cloud checks
  const geometry = new three.BoxGeometry(4, 3, 4); // Fluffy cloud block size
  const material = new three.MeshLambertMaterial({ 
    color: 0xffffff,
    transparent: true,
    opacity: 0.8
  });
  
  // Calculate max possible instances based on noise threshold
  let instanceCount = 0;
  const noise2D = SimplexNoise.createNoise2D();
  for (let x = 0; x < size; x++) {
    for (let z = 0; z < size; z++) {
      if (noise2D(x * 0.1, z * 0.1) > 0.3) instanceCount++;
    }
  }

  this.mesh = new three.InstancedMesh(geometry, material, instanceCount);
  
  const matrix = new three.Matrix4();
  let i = 0;
  for (let x = 0; x < size; x++) {
    for (let z = 0; z < size; z++) {
      if (noise2D(x * 0.1, z * 0.1) > 0.3) {
        matrix.setPosition((x - size/2) * spread, 60, (z - size/2) * spread);
        this.mesh.setMatrixAt(i, matrix);
        i++;
      }
    }
  }
  
  // Max distance they can drift before wrapping
  this.maxDisplacement = (size * spread) / 2;
  
  scene.add(this.mesh);
@@Clouds.constructor.end

@Clouds.update{delta: number, playerPos: any}: void
@@Clouds.update.code
  this.time += delta;
  const driftSpeed = 2.0;
  
  // Slowly drift
  let driftX = (this.time * driftSpeed) % this.maxDisplacement;
  let driftZ = (this.time * driftSpeed * 0.5) % this.maxDisplacement;
  
  // Keep clouds relatively centered over the player, but drifting
  // Snapping them in chunks to prevent floating point jitter at high values
  const snapX = Math.floor(playerPos.x / this.maxDisplacement) * this.maxDisplacement;
  const snapZ = Math.floor(playerPos.z / this.maxDisplacement) * this.maxDisplacement;

  this.mesh.position.set(snapX + driftX, 0, snapZ + driftZ);
@@Clouds.update.end

// --- Main App ---
MinecraftApp[MinecraftApp.ts{scene: any, camera: any, renderer: any, world: any, player: any, sun: any, time: number, selector: any, clock: any, clouds: any}]
MinecraftApp --> World
MinecraftApp --> Player

@MinecraftApp.constructor{}
@@MinecraftApp.constructor.code
  this.scene = new three.Scene();
  this.time = 0;
  this.clock = new three.Clock();
  this.camera = new three.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
  this.camera.position.set(8, 15, 8);
  this.camera.rotation.order = 'YXZ';

  this.renderer = new three.WebGLRenderer({ antialias: false });
  this.renderer.setSize(window.innerWidth, window.innerHeight);
  document.body.appendChild(this.renderer.domElement);

  const loader = new three.TextureLoader();
  const grassTex = loader.load('assets/grass.png'); grassTex.magFilter = three.NearestFilter;
  const brickTex = loader.load('assets/bricks.png'); brickTex.magFilter = three.NearestFilter;
  const glassTex = loader.load('assets/glass.png'); glassTex.magFilter = three.NearestFilter;

  const canvas = document.createElement('canvas');
  canvas.width = canvas.height = 32;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, 32, 32);
  ctx.strokeStyle = '#222222'; ctx.lineWidth = 4; ctx.strokeRect(2, 2, 28, 28);
  ctx.strokeStyle = '#999999'; ctx.lineWidth = 1; ctx.strokeRect(5, 5, 22, 22);
  
  const texFallback = new three.CanvasTexture(canvas);
  texFallback.magFilter = three.NearestFilter;
  
  const materials = {
      grass: new three.MeshLambertMaterial({ map: grassTex }),
      dirt: new three.MeshLambertMaterial({ map: texFallback, color: 0x7c5e3c }),
      stone: new three.MeshLambertMaterial({ map: texFallback, color: 0x808080 }),
      wood: new three.MeshLambertMaterial({ map: texFallback, color: 0x4c3314 }),
      water: new three.MeshLambertMaterial({ map: texFallback, color: 0xadd8e6, transparent: true, opacity: 0.8 }),
      tnt: new three.MeshLambertMaterial({ map: texFallback, color: 0xff0000 }),
      leaves: new three.MeshLambertMaterial({ map: texFallback, color: 0x2d5a27 }),
      bricks: new three.MeshLambertMaterial({ map: brickTex }),
      glass: new three.MeshLambertMaterial({ map: glassTex, transparent: true, opacity: 0.5, side: three.DoubleSide })
  };

  this.scene.fog = new three.Fog(0x87ceeb, 20, 60);

  this.world = new World(this.scene, materials);
  this.player = new Player(this.camera, this.scene);
  this.clouds = new Clouds(this.scene);

  this.selector = new three.Mesh(new three.BoxGeometry(1.02, 1.02, 1.02), new three.MeshBasicMaterial({ color: 0xffffff, wireframe: true, transparent: true, opacity: 0.5 }));
  this.scene.add(this.selector);
  
  // Lower light intensity to see colors
  this.sun = new three.DirectionalLight(0xffffff, 1.0);
  this.scene.add(this.sun, new three.AmbientLight(0xffffff, 0.4));

  window.addEventListener('mousedown', (e) => {
    if (document.pointerLockElement) this.handleInteraction(e.button === 0);
  });
  document.body.oncontextmenu = (e) => e.preventDefault();
  document.body.addEventListener('click', () => document.body.requestPointerLock());
  
  // Handle window resize
  window.addEventListener('resize', () => {
    this.camera.aspect = window.innerWidth / window.innerHeight;
    this.camera.updateProjectionMatrix();
    this.renderer.setSize(window.innerWidth, window.innerHeight);
  });
@@MinecraftApp.constructor.end

@MinecraftApp.handleInteraction{isBreaking: boolean}: void
@@MinecraftApp.handleInteraction.code
  this.player.raycaster.setFromCamera({x: 0, y: 0}, this.camera);
  let allMeshes = [];
  for (const chunk of this.world.chunks.values()) {
    allMeshes.push(...Object.values(chunk.meshes));
  }
  
  const intersects = this.player.raycaster.intersectObjects(allMeshes);
  
  if (intersects.length > 0) {
    const hit = intersects[0];
    const mesh = hit.object;
    const chunk = mesh.userData.chunk;
    if (!chunk) return;
    
    const m = new three.Matrix4();
    mesh.getMatrixAt(hit.instanceId, m);
    const localPos = new three.Vector3().setFromMatrixPosition(m);
    const worldPos = localPos.clone().add(chunk.group.position);

    if (isBreaking) {
      if (mesh.userData.type === 'tnt') {
         // BOOM!
         const radius = 4;
         for (let [key, cChunk] of this.world.chunks) {
            let needsUpdate = false;
            for (const t in cChunk.meshes) {
                const cMesh = cChunk.meshes[t];
                for(let i=0; i<cMesh.count; i++) {
                   const m2 = new three.Matrix4();
                   cMesh.getMatrixAt(i, m2);
                   if (m2.elements[0] === 0) continue; // Skip already destroyed blocks
                   
                   const pLocal = new three.Vector3().setFromMatrixPosition(m2);
                   const pWorld = pLocal.clone().add(cChunk.group.position);
                   if (pWorld.distanceTo(worldPos) <= radius) {
                      cMesh.setMatrixAt(i, new three.Matrix4().makeScale(0,0,0));
                      cChunk.voxels.delete(Math.round(pLocal.x) + "," + Math.round(pLocal.y) + "," + Math.round(pLocal.z));
                      needsUpdate = true;
                   }
                }
                if (needsUpdate) cMesh.instanceMatrix.needsUpdate = true;
            }
         }
         // Player knockback
         const dist = this.player.camera.position.distanceTo(worldPos);
         if (dist < 10) {
            this.player.velocity.y = (10 - dist) * 8; // Launch player up
         }
      } else {
        mesh.setMatrixAt(hit.instanceId, new three.Matrix4().makeScale(0, 0, 0));
        
        // Use m to get exact matrix before converting to localPos 
        const m = new three.Matrix4();
        mesh.getMatrixAt(hit.instanceId, m);
        const lPos = new three.Vector3().setFromMatrixPosition(m);

        chunk.voxels.delete(Math.round(lPos.x) + "," + Math.round(lPos.y) + "," + Math.round(lPos.z));
        mesh.instanceMatrix.needsUpdate = true;
        mesh.computeBoundingSphere();
      }
    } else {
      const activeTypes = ['grass', 'bricks', 'glass', 'wood', 'leaves', 'tnt'];
      const targetType = activeTypes[this.player.selectedBlock] || 'grass';
      const targetMesh = chunk.meshes[targetType];
      
      if (targetMesh.count >= chunk.maxInstances) return;
      localPos.add(hit.face.normal);
      m.setPosition(localPos);
      targetMesh.setMatrixAt(targetMesh.count, m);
      targetMesh.count++;
      targetMesh.instanceMatrix.needsUpdate = true;
      targetMesh.computeBoundingSphere();
      
      chunk.voxels.add(Math.round(localPos.x) + "," + Math.round(localPos.y) + "," + Math.round(localPos.z));
    }
  }
@@MinecraftApp.handleInteraction.end

@MinecraftApp.animate{}: void
@@MinecraftApp.animate.code
  requestAnimationFrame(() => this.animate());
  const delta = Math.min(this.clock.getDelta(), 0.1); // Real delta, capped to prevent spiral
  this.player.update(delta, this.world);
  this.world.update(this.camera.position);
  this.clouds.update(delta, this.camera.position);
  
  // Selector Logic
  this.player.raycaster.setFromCamera({x: 0, y: 0}, this.camera);
  let allMeshes = [];
  for (const chunk of this.world.chunks.values()) {
    allMeshes.push(...Object.values(chunk.meshes));
  }
  const intersects = this.player.raycaster.intersectObjects(allMeshes);
  if (intersects.length > 0) {
    const m = new three.Matrix4();
    intersects[0].object.getMatrixAt(intersects[0].instanceId, m);
    // add chunk.group position
    this.selector.position.setFromMatrixPosition(m).add(intersects[0].object.userData.chunk.group.position);
    this.selector.visible = true;
  } else { this.selector.visible = false; }

  // Day/night sky cycle
  this.time += delta * 0.05;
  this.sun.position.set(Math.cos(this.time) * 100, Math.sin(this.time) * 100, 0);
  const sunHeight = Math.sin(this.time);
  const dayColor = new three.Color(0x87ceeb);
  const duskColor = new three.Color(0xff7733);
  const nightColor = new three.Color(0x0a0a2e);
  let skyColor;
  if (sunHeight > 0.2) {
    skyColor = dayColor;
  } else if (sunHeight > -0.1) {
    const t = (sunHeight + 0.1) / 0.3;
    skyColor = nightColor.clone().lerp(duskColor, t < 0.5 ? t * 2 : 1).lerp(dayColor, t > 0.5 ? (t - 0.5) * 2 : 0);
  } else {
    skyColor = nightColor;
  }
  this.scene.background = skyColor;
  this.scene.fog.color.copy(skyColor);
  // Adjust ambient light with time of day
  this.sun.intensity = Math.max(0.1, sunHeight) * 1.5;
  this.renderer.render(this.scene, this.camera);
@@MinecraftApp.animate.end

