      onComplete: CompleteHandler | null
    }]
    
    @App.constructor
    @@App.constructor.code
      this.notes = [];
      this.isWorkPhase = true;
      this.timeLeft = 25 * 60; // 25 minutes in seconds
      this.timerInterval = null;
      this.onTick = null;
      this.onComplete = null;
    @@App.constructor.end

    @App.init{}: void
    @@App.init.code
      this.notes = this.loadNotes();
    @@App.init.end

    @App.loadNotes{}: string[]
    @@App.loadNotes.code
      try {
        const data = fs.readFileSync(path.join(electron.app.getPath('userData'), 'focus-notes.json'), 'utf8');
        return JSON.parse(data);
      } catch (e) {
        return [];
      }
    @@App.loadNotes.end

    @App.saveNotes{}: void
    @@App.saveNotes.code
      fs.writeFileSync(
        path.join(electron.app.getPath('userData'), 'focus-notes.json'),
        JSON.stringify(this.notes, null, 2)
      );
    @@App.saveNotes.end

    @App.addNote{text: string}: void
    @@App.addNote.code
      if (text.trim()) {
        this.notes.push(text.trim());
        this.saveNotes();
        if (this.window) {
          this.window.webContents.send('notes-updated', this.notes);
        }
      }
    @@App.addNote.end

    @App.start{}: void
    @@App.start.code
      if (this.timerInterval) return;
      this.timerInterval = setInterval(() => {
        this.timeLeft--;
        if (this.onTick) this.onTick(this.timeLeft, this.isWorkPhase);
        if (this.timeLeft <= 0) {
          clearInterval(this.timerInterval);
          this.timerInterval = null;
          if (this.onComplete) this.onComplete(this.isWorkPhase);
          // Switch phase
          this.isWorkPhase = !this.isWorkPhase;
          this.timeLeft = this.isWorkPhase ? 25 * 60 : 5 * 60;
        }
      }, 1000);
    @@App.start.end

    @App.pause{}: void
    @@App.pause.code
      if (this.timerInterval) {
        clearInterval(this.timerInterval);
        this.timerInterval = null;
      }
    @@App.pause.end

    @App.reset{}: void
    @@App.reset.code
      if (this.timerInterval) {
        clearInterval(this.timerInterval);
        this.timerInterval = null;
      }
      this.isWorkPhase = true;
      this.timeLeft = 25 * 60;
      if (this.onTick) this.onTick(this.timeLeft, this.isWorkPhase);
    @@App.reset.end

    %% ---- Electron Main Process ----
    @@main.code
      const { app, BrowserWindow, ipcMain, Tray, Menu } = electron;

      let mainWindow;
      let tray;
      let appInstance;

      function createWindow() {
        mainWindow = new BrowserWindow({
          width: 420,
          height: 680,
          resizable: false,
          backgroundColor: '#111827',
          webPreferences: {
            nodeIntegration: true,
            contextIsolation: false
          },
          titleBarStyle: 'hidden',
          frame: false,
          show: false
        });

        mainWindow.loadFile('index.html');

        mainWindow.once('ready-to-show', () => {
          mainWindow.show();
          if (appInstance) appInstance.window = mainWindow;
        });

        mainWindow.on('closed', () => {
          mainWindow = null;
          if (appInstance) appInstance.window = null;
        });
      }

      app.whenReady().then(() => {
        appInstance = new App();
        appInstance.init();
        createWindow();

        // Optional tray setup (check if icon exists)
        const iconPath = path.join(process.cwd(), 'icon.png');
        if (fs.existsSync(iconPath)) {
          tray = new Tray(iconPath);
          const contextMenu = Menu.buildFromTemplate([
            { label: 'Show', click: () => { if (mainWindow) mainWindow.show(); } },
            { label: 'Start Timer', click: () => appInstance.start() },
            { label: 'Pause Timer', click: () => appInstance.pause() },
            { label: 'Reset Timer', click: () => appInstance.reset() },
            { type: 'separator' },
            { label: 'Quit', click: () => app.quit() }
          ]);
          tray.setToolTip('Daily Focus');
          tray.setContextMenu(contextMenu);
          tray.on('click', () => { if (mainWindow) mainWindow.show(); });
        }

        // IPC handlers
        ipcMain.handle('get-notes', () => appInstance.notes);
        ipcMain.handle('add-note', (_, text) => {
          appInstance.addNote(text);
          return appInstance.notes;
        });

        ipcMain.on('timer-start', () => appInstance.start());
        ipcMain.on('timer-pause', () => appInstance.pause());
        ipcMain.on('timer-reset', () => appInstance.reset());

        // Forward timer events
        appInstance.onTick = (timeLeft, isWork) => {
          if (mainWindow) mainWindow.webContents.send('timer-tick', { timeLeft, isWork });
        };
        appInstance.onComplete = (wasWork) => {
          if (mainWindow) {
            mainWindow.webContents.send('timer-complete', wasWork);
            mainWindow.webContents.executeJavaScript(
              `new Audio('https://assets.mixkit.co/sfx/preview/mixkit-alarm-digital-clock-buzzer-989.mp3').play();`
            ).catch(() => {}); // Ignore audio errors
          }
        };
      });

      app.on('window-all-closed', () => {
        if (process.platform !== 'darwin') app.quit();
      });
    @@main.end

