          if (e.key === 'Enter') {
            const text = noteInput.value.trim();
            if (text) {
              ipcRenderer.invoke('add-note', text).then(renderNotes);
              noteInput.value = '';
            }
          }
        });

        document.getElementById('start').onclick = () => ipcRenderer.send('timer-start');
