// --- Classes ---

Ball[Ball.ts{mesh: any, vel: any, radius: number, isCue: boolean, active: boolean}]
@Ball.constructor{x: number, z: number, colorStr: string, isCue: boolean, isStripe: boolean}
@@Ball.constructor.code
  this.radius = 0.5;
  this.isCue = isCue;
  this.active = true;
  this.vel = new three.Vector3(0, 0, 0);
  
  const geometry = new three.SphereGeometry(this.radius, 32, 32);
  let material;
  
  if (isCue) {
    material = new three.MeshStandardMaterial({ color: 0xffffff, roughness: 0.1, metalness: 0.1 });
  } else {
    const canvas = document.createElement('canvas');
    canvas.width = 512;
    canvas.height = 256;
    const ctx = canvas.getContext('2d');
    
    if (isStripe) {
       ctx.fillStyle = '#ffffff';
       ctx.fillRect(0, 0, 512, 256);
       ctx.fillStyle = colorStr;
       ctx.fillRect(0, 64, 512, 128); // Stripe in middle
    } else {
       ctx.fillStyle = colorStr;
       ctx.fillRect(0, 0, 512, 256);
    }
    
    // Number circle (white circle on all non-cue balls)
    ctx.fillStyle = '#ffffff';
    ctx.beginPath();
    ctx.arc(256, 128, 40, 0, Math.PI*2);
    ctx.fill();
    
    const texture = new three.CanvasTexture(canvas);
    texture.anisotropy = 4;
    material = new three.MeshStandardMaterial({ 
      map: texture, 
      roughness: 0.1, 
      metalness: 0.1 
    });
  }
  
  this.mesh = new three.Mesh(geometry, material);
  this.mesh.position.set(x, this.radius, z);
  this.mesh.castShadow = true;
  this.mesh.userData = { isBall: true, ball: this };
@@Ball.constructor.end

@Ball.update{delta: number, friction: number, width: number, length: number}: void
@@Ball.update.code
  if (!this.active) return;
  
  // Apply velocity
  this.mesh.position.x += this.vel.x * delta;
  this.mesh.position.z += this.vel.z * delta;
  
  // Roll animation
  const speed = this.vel.length();
  if (speed > 0.01) {
    const axis = new three.Vector3(-this.vel.z, 0, this.vel.x).normalize();
    this.mesh.rotateOnWorldAxis(axis, (speed * delta) / this.radius);
  }
  
  // Apply friction
  this.vel.multiplyScalar(friction);
  if (this.vel.length() < 0.05) {
    this.vel.set(0,0,0);
  }
  
  // Box collision (Cushions)
  const restitution = 0.8;
  const hw = width / 2 - this.radius;
  const hl = length / 2 - this.radius;
  
  if (this.mesh.position.x > hw) {
      this.mesh.position.x = hw;
      this.vel.x *= -restitution;
  } else if (this.mesh.position.x < -hw) {
      this.mesh.position.x = -hw;
      this.vel.x *= -restitution;
  }
  
  if (this.mesh.position.z > hl) {
      this.mesh.position.z = hl;
      this.vel.z *= -restitution;
  } else if (this.mesh.position.z < -hl) {
      this.mesh.position.z = -hl;
      this.vel.z *= -restitution;
  }
@@Ball.update.end

Table[Table.ts{group: any, width: number, length: number, pockets: any[]}]
@Table.constructor{}
@@Table.constructor.code
  this.width = 10;
  this.length = 20;
  this.group = new three.Group();
  
  // Textures
  const loader = new three.TextureLoader();
  const feltTex = loader.load('assets/felt.jpg');
  feltTex.wrapS = three.RepeatWrapping;
  feltTex.wrapT = three.RepeatWrapping;
  feltTex.repeat.set(4, 8); // Tile the texture
  
  const woodTex = loader.load('assets/wood.jpg');
  woodTex.wrapS = three.RepeatWrapping;
  woodTex.wrapT = three.RepeatWrapping;
  woodTex.repeat.set(2, 4);
  
  // Felt surface
  const feltGeo = new three.BoxGeometry(this.width, 0.5, this.length);
  const feltMat = new three.MeshStandardMaterial({ 
    map: feltTex, 
    color: 0x008800, // Tint it strong green
    roughness: 0.9 
  });
  const felt = new three.Mesh(feltGeo, feltMat);
  felt.position.y = -0.25;
  felt.receiveShadow = true;
  this.group.add(felt);
  
  // Cushions (Edges)
  const cushionThickness = 1;
  const cushionHeight = 0.8;
  const cushionMat = new three.MeshStandardMaterial({ 
    map: woodTex,
    color: 0x8b5a2b, // Warm wood tint
    roughness: 0.6
  });
  
  const cTop = new three.Mesh(new three.BoxGeometry(this.width + cushionThickness*2, cushionHeight, cushionThickness), cushionMat);
  cTop.position.set(0, cushionHeight/2, -this.length/2 - cushionThickness/2);
  cTop.receiveShadow = true; cTop.castShadow = true;
  
  const cBot = new three.Mesh(new three.BoxGeometry(this.width + cushionThickness*2, cushionHeight, cushionThickness), cushionMat);
  cBot.position.set(0, cushionHeight/2, this.length/2 + cushionThickness/2);
  cBot.receiveShadow = true; cBot.castShadow = true;
  
  const cLeft = new three.Mesh(new three.BoxGeometry(cushionThickness, cushionHeight, this.length), cushionMat);
  cLeft.position.set(-this.width/2 - cushionThickness/2, cushionHeight/2, 0);
  cLeft.receiveShadow = true; cLeft.castShadow = true;
  
  const cRight = new three.Mesh(new three.BoxGeometry(cushionThickness, cushionHeight, this.length), cushionMat);
  cRight.position.set(this.width/2 + cushionThickness/2, cushionHeight/2, 0);
  cRight.receiveShadow = true; cRight.castShadow = true;
  
  this.group.add(cTop, cBot, cLeft, cRight);
  
  // Pockets
  this.pockets = [];
  const pRadius = 1.0; // Increased size
  const pGeo = new three.CylinderGeometry(pRadius, pRadius, 0.6, 16);
  const pMat = new three.MeshBasicMaterial({ color: 0x000000 });
  
  const hw = this.width / 2;
  const hl = this.length / 2;
  const pPositions = [
    [-hw, -hl], [hw, -hl], // Top corners
    [-hw, 0],   [hw, 0],   // Sides
    [-hw, hl],  [hw, hl]   // Bottom corners
  ];
  
  for(let pos of pPositions) {
     const pMesh = new three.Mesh(pGeo, pMat);
     pMesh.position.set(pos[0], 0.01, pos[1]);
     this.group.add(pMesh);
     this.pockets.push({x: pos[0], z: pos[1], radius: pRadius});
  }
@@Table.constructor.end

PoolGame[PoolGame.ts{scene: any, camera: any, renderer: any, clock: any, table: any, balls: any[], cueBall: any, isDragging: boolean, dragStart: any, dragLine: any, raycaster: any, mouse: any}]
PoolGame --> Table
