  %% ---- Electron Main Process ----
  @@main.code
    const { app, BrowserWindow, ipcMain } = electron;

    const todoManager = new TodoManager();

    function createWindow() {
      const win = new BrowserWindow({
        width: 800,
        height: 600,
        backgroundColor: '#0f172a',
        webPreferences: {
          nodeIntegration: true,
          contextIsolation: false
        }
      });

      win.loadFile('index.html');
      // win.webContents.openDevTools();
    }

    app.whenReady().then(() => {
      createWindow();

      app.on('activate', () => {
        if (BrowserWindow.getAllWindows().length === 0) createWindow();
      });
    });

    app.on('window-all-closed', () => {
      if (process.platform !== 'darwin') app.quit();
    });

    // IPC Handlers
    ipcMain.handle('get-tasks', () => todoManager.tasks);
    ipcMain.handle('add-task', (event, title) => {
      todoManager.addTask(title);
      return todoManager.tasks;
    });
    ipcMain.handle('toggle-task', (event, id) => {
      todoManager.toggleTask(id);
      return todoManager.tasks;
    });
    ipcMain.handle('delete-task', (event, id) => {
      todoManager.deleteTask(id);
      return todoManager.tasks;
    });
  @@main.end

  %% ---- UI Logic (web block) ----
  web->index.html.code
  <!DOCTYPE html>
  <html>
  <head>
    <title>SoT Electron Todo</title>
    <style>
      :root {
        --bg: #0f172a;
        --card: #1e293b;
        --text: #f1f5f9;
        --accent: #38bdf8;
        --danger: #ef4444;
