      }
      body {
        font-family: 'Inter', system-ui, sans-serif;
        background-color: var(--bg);
        color: var(--text);
        margin: 0;
        display: flex;
        justify-content: center;
        padding: 40px;
      }
      .container {
        width: 100%;
        max-width: 500px;
        background: var(--card);
        padding: 24px;
        border-radius: 12px;
        box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
        border: 1px solid #334155;
      }
      h1 { font-size: 24px; margin-bottom: 24px; text-align: center; color: var(--accent); }
      .input-group { display: flex; gap: 8px; margin-bottom: 24px; }
      input {
        flex: 1;
        background: #0f172a;
        border: 1px solid #334155;
        padding: 12px;
        border-radius: 6px;
        color: white;
        outline: none;
      }
      input:focus { border-color: var(--accent); }
      button.add-btn {
        background: var(--accent);
        color: #0f172a;
        border: none;
        padding: 0 20px;
        border-radius: 6px;
        font-weight: bold;
        cursor: pointer;
      }
      ul { list-style: none; padding: 0; }
      li {
        display: flex;
        align-items: center;
        padding: 12px;
        background: #0f172a;
        margin-bottom: 8px;
        border-radius: 6px;
        border: 1px solid #334155;
        transition: 0.2s;
      }
      li:hover { border-color: #475569; }
      .task-title { flex: 1; margin-left: 12px; cursor: pointer; }
      .completed { text-decoration: line-through; color: #64748b; }
      .delete-btn {
        background: transparent;
        color: #64748b;
        border: none;
        cursor: pointer;
        font-size: 18px;
      }
      .delete-btn:hover { color: var(--danger); }
      .checkbox {
        width: 18px;
        height: 18px;
        border: 2px solid var(--accent);
        border-radius: 4px;
        cursor: pointer;
        display: flex;
        align-items: center;
        justify-content: center;
      }
      .checkbox.checked { background: var(--accent); }
      .checkbox.checked::after { content: 'вң“'; color: #0f172a; font-size: 14px; font-weight: bold; }
    </style>
  </head>
  <body>
    <div class="container">
      <h1>SoT Tasks</h1>
      <div class="input-group">
        <input type="text" id="taskInput" placeholder="What needs to be done?">
        <button class="add-btn" onclick="addTask()">Add</button>
      </div>
      <ul id="taskList"></ul>
    </div>

    <script>
      const { ipcRenderer } = require('electron');

      const input = document.getElementById('taskInput');
      const list = document.getElementById('taskList');

      async function refreshTasks() {
        const tasks = await ipcRenderer.invoke('get-tasks');
        renderTasks(tasks);
      }

      function renderTasks(tasks) {
        list.innerHTML = '';
        tasks.forEach(task => {
          const li = document.createElement('li');
          li.innerHTML = `
            <div class="checkbox ${task.completed ? 'checked' : ''}" onclick="toggleTask(${task.id})"></div>
            <span class="task-title ${task.completed ? 'completed' : ''}" onclick="toggleTask(${task.id})">${task.title}</span>
            <button class="delete-btn" onclick="deleteTask(${task.id})">Г—</button>
          `;
          list.appendChild(li);
        });
      }

      async function addTask() {
        const title = input.value.trim();
        if (title) {
          const tasks = await ipcRenderer.invoke('add-task', title);
          input.value = '';
          renderTasks(tasks);
        }
      }

      async function toggleTask(id) {
        const tasks = await ipcRenderer.invoke('toggle-task', id);
        renderTasks(tasks);
      }

      async function deleteTask(id) {
        const tasks = await ipcRenderer.invoke('delete-task', id);
        renderTasks(tasks);
      }

      input.addEventListener('keypress', (e) => { if (e.key === 'Enter') addTask(); });
      refreshTasks();
    </script>
  </body>
  </html>
  web->index.html.end

twitter/auth.rawSource:
include->db.flow
extern->jwt from "jsonwebtoken"
extern->bcrypt from "bcrypt"

type->User {id: string, username: string, name: string, avatarUrl: string, followerCount: number, followingCount: number}
type->AuthResponse {token: string, refreshToken: string, user: User}

Auth[Auth.ts{db: any, jwtSecret: string, jwtRefreshSecret: string}]
Auth --> Database

@Auth.constructor{}
@@Auth.constructor.code
  this.db = new Database();
  this.jwtSecret = "super-secret-key-change-me";
  this.jwtRefreshSecret = "super-secret-refresh-key";
@@Auth.constructor.end

@async @Auth.init{}: void
@@Auth.init.code
  await this.db.init();
@@Auth.init.end

@async @Auth.register{username: string, name: string, pass: string}: AuthResponse
@@Auth.register.code
  const lowerUsername = username.toLowerCase();

  if (lowerUsername.includes('@')) {
    throw new Error("Username cannot contain '@' symbol");
  }

  const hash = await bcrypt.hash(pass, 10);
  try {
    const result = await this.db.query(
      "INSERT INTO users (username, name, password_hash) VALUES ($1, $2, $3) RETURNING id, username, name, avatar_url, follower_count, following_count",
      [lowerUsername, name, hash]
    );
    const row = result.rows[0];
    const user = { id: row.id, username: row.username, name: row.name, avatarUrl: row.avatar_url, followerCount: row.follower_count || 0, followingCount: row.following_count || 0 };
    return this.generateTokens(user);
  } catch (error) {
    throw new Error("User registration failed (possibly duplicate username)");
  }
@@Auth.register.end

@async @Auth.login{username: string, pass: string}: AuthResponse
@@Auth.login.code
  const lowerUsername = username.toLowerCase();
  const result = await this.db.query("SELECT * FROM users WHERE username = $1", [lowerUsername]);
  if (result.rows.length === 0) {
    throw new Error("User not found");
  }
  const userRow = result.rows[0];
  const valid = await bcrypt.compare(pass, userRow.password_hash);
  if (!valid) {
    throw new Error("Invalid password");
  }

  const user = { id: userRow.id, username: userRow.username, name: userRow.name, avatarUrl: userRow.avatar_url, followerCount: userRow.follower_count || 0, followingCount: userRow.following_count || 0 };
  return this.generateTokens(user);
@@Auth.login.end

@Auth.generateTokens{user: User}: AuthResponse
@@Auth.generateTokens.code
  const token = jwt.sign(user, this.jwtSecret, { expiresIn: "1h" });
  const refreshToken = jwt.sign(user, this.jwtRefreshSecret, { expiresIn: "7d" });
  return { token, refreshToken, user };
@@Auth.generateTokens.end

@Auth.refresh{refreshToken: string}: AuthResponse
@@Auth.refresh.code
  try {
    // Note: The prompt asks for 10 minute refresh via the client. This endpoint verifies
    // the long-lived refresh token and returns a fresh 1h token. The client can call this
    // every 10 mins.
    const decoded = jwt.verify(refreshToken, this.jwtRefreshSecret);
    const user = { id: decoded.id, username: decoded.username, name: decoded.name, avatarUrl: decoded.avatarUrl, followerCount: decoded.followerCount || 0, followingCount: decoded.followingCount || 0 };
    return this.generateTokens(user);
  } catch (err) {
    throw new Error("Invalid or expired refresh token");
  }
@@Auth.refresh.end

@Auth.verifyToken{token: string}: User
@@Auth.verifyToken.code
  try {
    return jwt.verify(token, this.jwtSecret);
  } catch (err) {
    throw new Error("Invalid or expired token");
  }
@@Auth.verifyToken.end

