@async @Database.init{}: void
@@Database.init.code


  await this.pool.query("CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), username VARCHAR(255) UNIQUE NOT NULL, name VARCHAR(255) NOT NULL, password_hash VARCHAR(255) NOT NULL, avatar_url TEXT);");
  await this.pool.query("ALTER TABLE users ADD COLUMN IF NOT EXISTS follower_count INT DEFAULT 0;");
  await this.pool.query("ALTER TABLE users ADD COLUMN IF NOT EXISTS following_count INT DEFAULT 0;");
  await this.pool.query("ALTER TABLE users ADD COLUMN IF NOT EXISTS banner_url TEXT;");
  await this.pool.query("CREATE TABLE IF NOT EXISTS messages (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), sender_username VARCHAR(255) NOT NULL, receiver_username VARCHAR(255) NOT NULL,content TEXT NOT NULL,timestamp BIGINT NOT NULL,replied_to_id UUID,retweeted_id UUID,liked_count INT DEFAULT 0, retweet_count INT DEFAULT 0, image_url TEXT);");
  await this.pool.query("CREATE TABLE IF NOT EXISTS likes ( id SERIAL PRIMARY KEY, message_id UUID NOT NULL REFERENCES messages(id), username VARCHAR(255) NOT NULL, UNIQUE(message_id, username));");
  await this.pool.query("CREATE TABLE IF NOT EXISTS follows (follower_username VARCHAR(255) NOT NULL, following_username VARCHAR(255) NOT NULL, UNIQUE(follower_username, following_username));");
  await this.pool.query("CREATE TABLE IF NOT EXISTS hashtags (tag VARCHAR(255) NOT NULL, message_id UUID NOT NULL REFERENCES messages(id) ON DELETE CASCADE, PRIMARY KEY (tag, message_id));");
  await this.pool.query("CREATE TABLE IF NOT EXISTS notifications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), sender_username VARCHAR(255) NOT NULL, receiver_username VARCHAR(255) NOT NULL, action VARCHAR(255) NOT NULL, message_id UUID, timestamp BIGINT NOT NULL, is_read BOOLEAN DEFAULT FALSE, UNIQUE(sender_username, receiver_username, action, message_id));");

  console.log("Database initialized (Fresh start).");
@@Database.init.end

@async @Database.insertMessage{senderUsername: string, receiverUsername: string, content: string, timestamp: number, repliedToId: string, retweetedId: string, imageUrl: string}: any
@@Database.insertMessage.code
  if (content && content.length > 300) {
    throw new Error("Message content exceeds 300 characters");
  }
  const client = await this.pool.connect();
  try {
    await client.query('BEGIN');
    const res = await client.query(
      "INSERT INTO messages (sender_username, receiver_username, content, timestamp, replied_to_id, retweeted_id, image_url) VALUES ($1, $2, $3, $4, $5, $6, $7) RETURNING *",
      [senderUsername, receiverUsername, content, timestamp, repliedToId || null, retweetedId || null, imageUrl || null]
    );
    const message = res.rows[0];

    // Extract hashtags
    const hashtags = content.match(/#(\w+)/g);
    if (hashtags) {
      for (const t of hashtags) {
        const tag = t.substring(1).toLowerCase();
        await client.query(
          "INSERT INTO hashtags (tag, message_id) VALUES ($1, $2) ON CONFLICT DO NOTHING",
          [tag, message.id]
        );
      }
    }

    // Notification for replies
    if (repliedToId) {
      const parentRes = await client.query("SELECT sender_username FROM messages WHERE id = $1", [repliedToId]);
      if (parentRes.rows.length > 0) {
        const parentOwner = parentRes.rows[0].sender_username;
        if (parentOwner !== senderUsername) {
           await client.query(
             "INSERT INTO notifications (sender_username, receiver_username, action, message_id, timestamp) VALUES ($1, $2, $3, $4, $5) ON CONFLICT DO NOTHING",
             [senderUsername, parentOwner, 'reply', message.id, timestamp]
           );
        }
      }
    }

    await client.query('COMMIT');
    return message;
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
  }
@@Database.insertMessage.end

