@async @Database.likeMessage{messageId: string, username: string}: void
@@Database.likeMessage.code
  const client = await this.pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('INSERT INTO likes (message_id, username) VALUES ($1, $2)', [messageId, username]);
    await client.query('UPDATE messages SET liked_count = liked_count + 1 WHERE id = $1', [messageId]);

    // Notification for like
    const msgRes = await client.query("SELECT sender_username FROM messages WHERE id = $1", [messageId]);
    if (msgRes.rows.length > 0) {
      const owner = msgRes.rows[0].sender_username;
      if (owner !== username) {
        await client.query(
          "INSERT INTO notifications (sender_username, receiver_username, action, message_id, timestamp) VALUES ($1, $2, $3, $4, $5) ON CONFLICT DO NOTHING",
          [username, owner, 'like', messageId, Date.now()]
        );
      }
    }

    await client.query('COMMIT');
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
  }
@@Database.likeMessage.end

@async @Database.unlikeMessage{messageId: string, username: string}: void
@@Database.unlikeMessage.code
  const client = await this.pool.connect();
  try {
    await client.query('BEGIN');
    const res = await client.query('DELETE FROM likes WHERE message_id = $1 AND username = $2', [messageId, username]);
    if (res.rowCount > 0) {
      await client.query('UPDATE messages SET liked_count = liked_count - 1 WHERE id = $1', [messageId]);
    }
    await client.query('COMMIT');
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
  }
@@Database.unlikeMessage.end

@async @Database.retweetMessage{sender: string, originalId: string, ts: number}: any
@@Database.retweetMessage.code
  const client = await this.pool.connect();
  try {
    await client.query('BEGIN');

    // 1. Get original tweet info (need sender_username for return object)
    const origRes = await client.query('SELECT sender_username, content, image_url FROM messages WHERE id = $1', [originalId]);
    if (origRes.rows.length === 0) {
      throw new Error("Original tweet not found (" + originalId + ")");
    }
    const origRow = origRes.rows[0];

    // 2. Prevent self-retweet
    if (origRow.sender_username === sender) {
      throw new Error("You cannot retweet your own tweet");
    }

    // 3. Check for existing retweet by this user
    const existing = await client.query(
      'SELECT id FROM messages WHERE sender_username = $1 AND retweeted_id = $2',
      [sender, originalId]
    );
    if (existing.rows.length > 0) {
      throw new Error("You have already retweeted this message");
    }

    // 4. Create retweet record
    const retweet = await client.query(
      "INSERT INTO messages (sender_username, receiver_username, content, timestamp, retweeted_id, image_url) VALUES ($1, '', $2, $3, $4, $5) RETURNING *",
      [sender, origRow.content, ts, originalId, origRow.image_url]
    );

    // 5. Create hashtags for retweet
    const hashtags = origRow.content.match(/#(\w+)/g);
    const retweetRow = retweet.rows[0];
    if (hashtags) {
      for (const t of hashtags) {
        const tag = t.substring(1).toLowerCase();
        await client.query(
          "INSERT INTO hashtags (tag, message_id) VALUES ($1, $2) ON CONFLICT DO NOTHING",
          [tag, retweetRow.id]
        );
      }
    }

    // 6. Increment original retweet count
    await client.query('UPDATE messages SET retweet_count = retweet_count + 1 WHERE id = $1', [originalId]);

    // Notification for retweet
    if (origRow.sender_username !== sender) {
       await client.query(
         "INSERT INTO notifications (sender_username, receiver_username, action, message_id, timestamp) VALUES ($1, $2, $3, $4, $5) ON CONFLICT DO NOTHING",
         [sender, origRow.sender_username, 'retweet', originalId, ts]
       );
    }

    await client.query('COMMIT');

    const row = retweet.rows[0];
    return {
      id: row.id,
      authorUsername: row.sender_username,
      content: row.content,
      timestamp: Number(row.timestamp),
      retweetedId: row.retweeted_id,
      retweetedAuthor: origRow.sender_username,
      likedCount: 0,
      retweetCount: 0,
      repliesCount: 0,
      imageUrl: row.image_url
    };
  } catch (e) {
    if (client) await client.query('ROLLBACK');
    console.error("[DB ERROR] retweetMessage:", e.name, e.message);
    throw e;
  } finally {
    if (client) client.release();
  }
@@Database.retweetMessage.end

