@async @Database.followUser{follower: string, following: string}: void
@@Database.followUser.code
  const client = await this.pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('INSERT INTO follows (follower_username, following_username) VALUES ($1, $2)', [follower, following]);
    await client.query('UPDATE users SET follower_count = follower_count + 1 WHERE username = $1', [following]);
    await client.query('UPDATE users SET following_count = following_count + 1 WHERE username = $1', [follower]);

    // Notification for follow: Check if one already exists to avoid spam
    const existingNotif = await client.query(
      "SELECT id FROM notifications WHERE sender_username = $1 AND receiver_username = $2 AND action = 'follow'",
      [follower, following]
    );


    if (existingNotif.rows.length === 0) {
      await client.query(
        "INSERT INTO notifications (sender_username, receiver_username, action, timestamp) VALUES ($1, $2, $3, $4)",
        [follower, following, 'follow', Date.now()]
      );
    } else {
      // Optional: Just update the timestamp and mark as unread to "bump" it
      await client.query(
        "UPDATE notifications SET timestamp = $1, is_read = FALSE WHERE id = $2",
        [Date.now(), existingNotif.rows[0].id]
      );
    }

    await client.query('COMMIT');
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
  }
@@Database.followUser.end

@async @Database.unfollowUser{follower: string, following: string}: void
@@Database.unfollowUser.code
  const client = await this.pool.connect();
  try {
    await client.query('BEGIN');
    const res = await client.query('DELETE FROM follows WHERE follower_username = $1 AND following_username = $2', [follower, following]);
    if (res.rowCount > 0) {
      await client.query('UPDATE users SET follower_count = GREATEST(0, follower_count - 1) WHERE username = $1', [following]);
      await client.query('UPDATE users SET following_count = GREATEST(0, following_count - 1) WHERE username = $1', [follower]);
    }
    await client.query('COMMIT');
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
  }
@@Database.unfollowUser.end

