@async @Database.getUser{username: string}: any
@@Database.getUser.code
  const res = await this.pool.query("SELECT * FROM users WHERE username = $1", [username]);
  return res.rows[0] || null;
@@Database.getUser.end

@async @Database.updateUserAvatar{username: string, avatarUrl: string}: void
@@Database.updateUserAvatar.code
  await this.pool.query("UPDATE users SET avatar_url = $1 WHERE username = $2", [avatarUrl, username]);
@@Database.updateUserAvatar.end

@async @Database.updateUserBanner{username: string, bannerUrl: string}: void
@@Database.updateUserBanner.code
  await this.pool.query("UPDATE users SET banner_url = $1 WHERE username = $2", [bannerUrl, username]);
@@Database.updateUserBanner.end

@async @Database.getTrendingHashtags{last24HoursMs: number, limit: number}: any
@@Database.getTrendingHashtags.code
  const res = await this.pool.query(
    "SELECT h.tag, COUNT(*) as count " +
    "FROM hashtags h " +
    "JOIN messages m ON h.message_id = m.id " +
    "WHERE m.timestamp > $1 " +
    "GROUP BY h.tag " +
    "ORDER BY count DESC " +
    "LIMIT $2",
    [last24HoursMs, limit || 10]
  );
  return res.rows.map(row => ({
    tag: row.tag,
    count: Number(row.count)
  }));
@@Database.getTrendingHashtags.end

@async @Database.getNotifications{username: string, limit: number, offset: number}: any
@@Database.getNotifications.code
  const l = limit || 25;
  const o = offset || 0;
  const res = await this.pool.query(
    "SELECT n.*, u.avatar_url as sender_avatar, u.name as sender_name, m.content as message_content, " +
    "(SELECT content FROM messages WHERE id = m.replied_to_id) as parent_content " +
    "FROM notifications n " +
    "JOIN users u ON n.sender_username = u.username " +
    "LEFT JOIN messages m ON n.message_id = m.id " +
    "WHERE n.receiver_username = $1 " +
    "ORDER BY n.timestamp DESC LIMIT $2 OFFSET $3",
    [username, l, o]
  );
  return res.rows.map(row => ({
    id: row.id,
    from: row.sender_username,
    fromName: row.sender_name,
    fromAvatar: row.sender_avatar,
    to: row.receiver_username,
    action: row.action,
    messageId: row.message_id,
    messageContent: row.message_content,
    parentContent: row.parent_content,
    timestamp: Number(row.timestamp),
    isRead: row.is_read
  }));
@@Database.getNotifications.end

@async @Database.markNotificationsRead{username: string}: void
@@Database.markNotificationsRead.code
  await this.pool.query("UPDATE notifications SET is_read = TRUE WHERE receiver_username = $1", [username]);
@@Database.markNotificationsRead.end

@async @Database.query{text: string, params: any}: any
@@Database.query.code
  return await this.pool.query(text, params);
@@Database.query.end

