twitter/frontend.rawSource:
include->authfe.flow
include->feeds.flow
include->messages.flow

cliscripts->start node -e "require('fs').copyFileSync('compiled.js', 'public/compiled.js')" && npx -y http-server public -p 3000

TwitterApp[TwitterApp.ts{auth: any, feed: any, messaging: any, initialized: boolean, followedUsers: Set<string>, currentSocialUser: string, currentSocialType: string}]
TwitterApp --> AuthFE
TwitterApp --> Feed
TwitterApp --> Messaging

@TwitterApp.constructor{}
@@TwitterApp.constructor.code
  this.auth = new AuthFE();
  this.feed = new Feed();
  this.messaging = new Messaging();
  this.initialized = false;
  this.renderCount = 0;
  this.tweetsOffset = 0;
  this.profileTweetsOffset = 0;
  this.notificationsOffset = 0;
  this.tweetsLimit = 25;
  this.followedUsers = new Set();
  this.currentSocialUser = "";
  this.currentSocialType = "";
@@TwitterApp.constructor.end

@async @TwitterApp.init{}: void
@@TwitterApp.init.code
  if (this.initialized) return;
  this.initialized = true;

  // Create toast container
  if (!document.getElementById('toast-container')) {
    const container = document.createElement('div');
    container.id = 'toast-container';
    document.body.appendChild(container);
  }

  if (this.auth.token) {
    try {
      await this.auth.refresh();
    } catch (e) {
      console.warn("Session expired or refresh failed:", e);
      // Optional: redirect to login if refresh fails
    }
    await this.fetchFollowing();
  }
@@TwitterApp.init.end

@async @TwitterApp.renderTimeline{containerId: string}: void
@@TwitterApp.renderTimeline.code
  await this.loadTimeline(containerId, false);
@@TwitterApp.renderTimeline.end

@async @TwitterApp.renderUserTimeline{containerId: string, username: string, append: boolean}: void
@@TwitterApp.renderUserTimeline.code
    const container = document.getElementById(containerId);
    if (!container) return;
    
    if (!append) {
      this.profileTweetsOffset = 0;
      container.innerHTML = "<div class='loading'>Loading timeline...</div>";
    }

    try {
      const tweets = await this.feed.getUserTweets(username, this.tweetsLimit, this.profileTweetsOffset); 
      
      if (!append) container.innerHTML = "";
      
      if (tweets.length === 0) {
        if (!append) {
          container.innerHTML = "<div class='empty-timeline'>No messages yet.</div>";
        } else {
          this.showToast("No more messages", "info");
        }
        const loadMoreBtn = document.getElementById('loadMoreBtn');
        if (loadMoreBtn) loadMoreBtn.style.display = 'none';
        return;
      }

      let html = "";
      for (const t of tweets) {
        html += this.renderSingleTweet(t);
      }
      
      if (append) {
        container.innerHTML += html;
      } else {
        container.innerHTML = html;
      }
      
      this.profileTweetsOffset += tweets.length;
      
      // Update Load More button
      const loadMoreBtn = document.getElementById('loadMoreBtn');
      if (loadMoreBtn) {
        loadMoreBtn.style.display = tweets.length < this.tweetsLimit ? 'none' : 'block';
        loadMoreBtn.onclick = () => this.renderUserTimeline(containerId, username, true);
      }
    } catch (e) {
      this.showToast(e.message, 'error');
    }
@@TwitterApp.renderUserTimeline.end

@async @TwitterApp.getUserInfo{username: string}: any
@@TwitterApp.getUserInfo.code
    const res = await fetch("http://localhost:8080/api/user?username=" + username);
    if (!res.ok) throw new Error("User not found");
    return await res.json();
@@TwitterApp.getUserInfo.end

  @async @TwitterApp.renderTrending{containerId: string}: void
  @@TwitterApp.renderTrending.code
    const container = document.getElementById(containerId);
    if (!container) return;

    try {
      const trending = await this.feed.getTrending();
      if (!trending || trending.length === 0) {
        container.style.display = 'none';
        return;
      }

      container.style.display = 'block';
      let html = "<h3>Trends for you</h3>";
      trending.forEach(t => {
        html += 
          "<div class='trending-item' onclick='window.app.showHashtagTimeline(\"" + t.tag + "\")'>" +
            "<div class='trending-tag'>#" + t.tag + "</div>" +
            "<div class='trending-count'>" + t.count + " Tweets</div>" +
          "</div>";
      });
      container.innerHTML = html;
    } catch (e) {
      console.error("Failed to render trending:", e);
      container.style.display = 'none';
    }
  @@TwitterApp.renderTrending.end

  @async @TwitterApp.renderNotifications{containerId: string, append: boolean}: void
  @@TwitterApp.renderNotifications.code
    const container = document.getElementById(containerId);
    if (!container) return;

    if (!append) {
      this.notificationsOffset = 0;
      container.innerHTML = "<div class='loading'>Loading notifications...</div>";
    }

    try {
      const notifications = await this.feed.getNotifications(this.tweetsLimit, this.notificationsOffset);
      
      if (!append) container.innerHTML = "";

      if (!notifications || notifications.length === 0) {
        if (!append) {
          container.innerHTML = "<div class='empty-notifications'>No notifications yet.</div>";
        } else {
          this.showToast("No more notifications", "info");
        }
        const loadMoreBtn = document.getElementById('loadMoreBtn');
        if (loadMoreBtn) loadMoreBtn.style.display = 'none';
        return;
      }

      let html = (!append ? "<h3>Notifications</h3>" : "");
      notifications.forEach(n => {
        const time = this.formatRelativeTime(n.timestamp);
        let actionText = "";
        let icon = "";
        if (n.action === 'like') { actionText = "liked your tweet"; icon = "вқӨпёҸ"; }
        else if (n.action === 'follow') { actionText = "followed you"; icon = "рҹ‘Ө"; }
        else if (n.action === 'retweet') { actionText = "retweeted your tweet"; icon = "рҹ”„"; }
        else if (n.action === 'reply') { actionText = "replied to your tweet"; icon = "рҹ’¬"; }

        html += 
          "<div class='notification-item " + (n.isRead ? "" : "unread") + "' id='notification-" + n.id + "'>" +
            "<img src='" + (n.fromAvatar || 'http://localhost:8080/images/userprofiledefault.png') + "' alt='Notification avatar' class='notification-avatar'>" +
            "<div class='notification-content'>" +
              "<div><span class='notification-user'>@" + n.from + "</span> " + actionText + " " + icon + "</div>" +
              (n.parentContent ? "<div class='notification-parent-preview' style='font-size: 0.85em; opacity: 0.6; margin: 4px 0; padding-left: 8px; border-left: 2px solid var(--border-color); margin-top: 4px; font-style: italic;'>Replying to: \"" + n.parentContent + "\"</div>" : "") +
              (n.messageContent ? "<div class='notification-message-preview'>\"" + n.messageContent + "\"</div>" : "") +
              "<div class='notification-time'>" + time + "</div>" +
              "<div class='notification-actions' style='margin-top: 8px; display: flex; gap: 10px;'>" +
                (n.action === 'reply' ? "<button class='btn btn-outline btn-compact' onclick=\"window.app.startReply('" + n.messageId + "', '" + n.from + "', 'notif-" + n.id + "')\"> Reply Back</button>" : "") +
                (n.action === 'follow' && !this.followedUsers.has(n.from) ? "<button class='btn btn-primary btn-compact' id='follow-back-" + n.from + "' style='width:auto;' onclick=\"window.app.toggleFollow('" + n.from + "', 0)\">рҹ‘Ө Follow Back</button>" : "") +
              "</div>" +
              "<div id='replies-instance-notif-" + n.id + "' class='replies-container' style='display: none;'></div>" +
            "</div>" +
          "</div>";
      });
      
      if (append) {
        container.innerHTML += html;
      } else {
        container.innerHTML = html;
        // Mark as read immediately when viewed (only on initial load)
        this.feed.markNotificationsRead();
        const navBadge = document.getElementById('notifications-badge');
        if (navBadge) navBadge.style.display = 'none';
      }

      this.notificationsOffset += notifications.length;
      
      // Update Load More button
      const loadMoreBtn = document.getElementById('loadMoreBtn');
      if (loadMoreBtn) {
        loadMoreBtn.style.display = notifications.length < this.tweetsLimit ? 'none' : 'block';
        loadMoreBtn.onclick = () => this.renderNotifications(containerId, true);
      }
    } catch (e) {
      console.error("Failed to render notifications:", e);
      this.showToast("Error loading notifications", "error");
    }
  @@TwitterApp.renderNotifications.end

  @async @TwitterApp.checkNotifications{}: void
  @@TwitterApp.checkNotifications.code
    try {
      const notifications = await this.feed.getNotifications();
      const unreadCount = notifications.filter(n => !n.isRead).length;
      const navBadge = document.getElementById('notifications-badge');
      if (navBadge) {
        if (unreadCount > 0) {
          navBadge.innerText = unreadCount > 9 ? "9+" : unreadCount;
          navBadge.style.display = 'block';
        } else {
          navBadge.style.display = 'none';
        }
      }
    } catch (e) {
      console.error("Failed to check notifications:", e);
    }
  @@TwitterApp.checkNotifications.end

@async @TwitterApp.loadTimeline{containerId: string, append: boolean}: void
@@TwitterApp.loadTimeline.code
  const container = document.getElementById(containerId);
  if (!container) return;
  
  if (!append) {
    this.tweetsOffset = 0;
    container.innerHTML = '';
  }
  
  const tweets = await this.feed.getTimeline(this.tweetsLimit, this.tweetsOffset);
  
  if (tweets.length === 0) {
    if (append) {
      this.showToast("No more tweets to load", "info");
      const loadMoreBtn = document.getElementById('loadMoreBtn');
      if (loadMoreBtn) loadMoreBtn.style.display = 'none';
    } else {
      container.innerHTML = '<div style="padding: 20px; text-align: center; color: var(--text-secondary);">No tweets yet!</div>';
    }
    return;
  }
  
  let html = '';
  tweets.forEach(t => {
    html += this.renderSingleTweet(t);
  });
  
  if (append) {
    container.innerHTML += html;
  } else {
    container.innerHTML = html;
  }
  
  this.tweetsOffset += tweets.length;
  
  // Show/Hide load more button based on if we got a full page
  const loadMoreBtn = document.getElementById('loadMoreBtn');
  if (loadMoreBtn) {
    loadMoreBtn.style.display = tweets.length < this.tweetsLimit ? 'none' : 'block';
    loadMoreBtn.onclick = () => this.loadMore(containerId);
  }
@@TwitterApp.loadTimeline.end

@async @TwitterApp.loadMore{containerId: string}: void
@@TwitterApp.loadMore.code
  await this.loadTimeline(containerId, true);
@@TwitterApp.loadMore.end

@TwitterApp.renderSingleTweet{t: any}: string
@@TwitterApp.renderSingleTweet.code
  const instanceId = ++this.renderCount;
  const name = t.authorName || t.authorUsername;
  const isRetweet = !!t.retweetedId;
  const retweetTag = isRetweet ? "<span class=\"retweet-tag\">рҹ”„ Retweeted from @" + t.retweetedAuthor + "</span>" : "";
    const currentUser = this.auth.getCurrentUser();
    const canRetweet = currentUser && currentUser.username !== t.authorUsername;
    const retweetBtn = canRetweet ?
    "<button class=\"tweet-btn retweet-btn\" id=\"retweet-btn-instance-" + instanceId + "\" onclick=\"window.app.retweet('" + t.id + "', " + instanceId + ")\">рҹ”„ " + (t.retweetCount || 0) + "</button>" : "";
    
    const avatarUrl = t.authorAvatar || 'http://localhost:8080/images/userprofiledefault.png';
    const avatarHtml = "<a href=\"profile.html?username=" + t.authorUsername + "\"><img src=\"" + avatarUrl + "\" alt=\"" + t.authorUsername + "'s avatar\" class=\"tweet-avatar\"></a>";
    const imageHtml = t.imageUrl ? "<div class=\"tweet-image-container\"><img src=\"" + t.imageUrl + "\" alt=\"Tweet image\" class=\"tweet-image\"></div>" : "";

    const isFollowing = this.followedUsers.has(t.authorUsername);
    const isSelf = currentUser && currentUser.username === t.authorUsername;
    const followBtn = (!isSelf && currentUser) ? 
      "<button class=\"tweet-btn follow-btn\" id=\"twitter-follow-" + t.authorUsername + "\" onclick=\"window.app.toggleFollow('" + t.authorUsername + "', " + (t.authorFollowerCount || 0) + ")\">" + (isFollowing ? "Unfollow" : "Follow") + "</button>" : "";

    const highlightedContent = t.content.replace(/#(\w+)/g, '<span class="hashtag" onclick="event.stopPropagation(); window.app.showHashtagTimeline(\'$1\')">#$1</span>');
    const replyContextHtml = t.repliedToUsername ? 
      "<div class='tweet-reply-context' style='margin-bottom: 8px; font-size: 0.9em;'>" +
        "<span style='color: var(--text-secondary);'>Replying to </span>" +
        "<a href='profile.html?username=" + t.repliedToUsername + "' class='tweet-name-link' style='color: var(--primary-color); font-weight: bold;'>@" + t.repliedToUsername + "</a>" +
        (t.parentContent ? "<div class='tweet-parent-preview' style='opacity: 0.6; padding-left: 10px; border-left: 2px solid var(--border-color); margin-top: 4px; font-style: italic;'>\"" + t.parentContent + "\"</div>" : "") +
      "</div>" : "";

    return "<div class=\"tweet\" id=\"tweet-instance-" + instanceId + "\">" +
    "<div class=\"tweet-header\">" +
    avatarHtml +
    "<div class=\"tweet-header-info\">" +
    "<div class=\"tweet-header-top\">" +
    "<a href=\"profile.html?username=" + t.authorUsername + "\" class=\"tweet-name-link\"><span class=\"tweet-name\">" + name + "</span></a>" +
    "<a href=\"profile.html?username=" + t.authorUsername + "\" style=\"text-decoration:none; color:inherit;\"><span class=\"tweet-username\">@" + t.authorUsername + "</span></a>" +
    "<span class=\"tweet-username\">В· " + this.formatRelativeTime(t.timestamp) + "</span>" +
    "<span class=\"tweet-followers\" id=\"followers-count-" + instanceId + "\">рҹ‘Ө " + (t.authorFollowerCount || 0) + "</span>" +
    "</div>" +
    retweetTag +
    "</div>" +
    followBtn +
    "</div>" +
    "<div class=\"tweet-content\">" + replyContextHtml + highlightedContent + "</div>" +
    imageHtml +
    "<div class=\"tweet-footer\">" +
        "<button class=\"tweet-btn reply-btn\" onclick=\"window.app.startReply('" + t.id + "', '" + t.authorUsername + "', " + instanceId + ")\">рҹ’¬ " + (t.repliesCount || 0) + "</button>" +
        retweetBtn +
        "<button class=\"tweet-btn like-btn\" id=\"like-btn-instance-" + instanceId + "\" onclick=\"window.app.like('" + t.id + "', " + instanceId + ")\">вқӨпёҸ " + (t.likedCount || 0) + "</button>" +
        "<button class=\"tweet-btn view-replies-btn\" onclick=\"window.app.toggleReplies('" + t.id + "', " + instanceId + ")\">View Replies</button>" +
      "</div>" +
