@async @TwitterApp.loadHashtagTimeline{tag: string, append: boolean}: void
@@TwitterApp.loadHashtagTimeline.code
  const container = document.getElementById('hashtag-timeline-content');
  if (!container) return;
  
  if (!append) {
    this.tweetsOffset = 0;
    container.innerHTML = '';
  }
  
  const tweets = await this.feed.getHashtagFeed(tag, this.tweetsLimit, this.tweetsOffset);
  
  if (tweets.length === 0) {
    if (!append) {
      container.innerHTML = '<div style="padding: 20px; text-align: center; color: var(--text-secondary);">No tweets found for #' + tag + '</div>';
    } else {
      this.showToast("No more tweets to load", "info");
      const loadMoreBtn = document.getElementById('loadMoreBtn');
      if (loadMoreBtn) loadMoreBtn.style.display = 'none';
    }
    return;
  }
  
  let html = '';
  tweets.forEach(t => {
    html += this.renderSingleTweet(t);
  });
  
  if (append) {
    container.innerHTML += html;
  } else {
    container.innerHTML = html;
  }
  
  this.tweetsOffset += tweets.length;
  
  const loadMoreBtn = document.getElementById('loadMoreBtn');
  if (loadMoreBtn) {
    loadMoreBtn.style.display = tweets.length < this.tweetsLimit ? 'none' : 'block';
    loadMoreBtn.onclick = () => this.loadHashtagTimeline(tag, true);
  }
@@TwitterApp.loadHashtagTimeline.end

@TwitterApp.formatRelativeTime{timestamp: number}: string
@@TwitterApp.formatRelativeTime.code
  if (!timestamp) return "just now";
  const now = Date.now();
  const diff = now - timestamp;
  if (diff < 0) return "just now";
  
  const seconds = Math.floor(diff / 1000);
  const minutes = Math.floor(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);
  const weeks = Math.floor(days / 7);
  const months = Math.floor(days / 30);
  const years = Math.floor(days / 365);

  if (seconds < 60) return "just now";
  if (minutes < 60) return minutes + "m ago";
  if (hours < 24) return hours + "h ago";
  if (days < 7) return days + "d ago";
  if (weeks < 4) return weeks + "w ago";
  if (months < 12) return months + "mo ago";
  return years + "y ago";
@@TwitterApp.formatRelativeTime.end

