@async @TwitterApp.toggleFollow{username: string, currentCount: number}: void
@@TwitterApp.toggleFollow.code
  const isFollowing = this.followedUsers.has(username);
  
  try {
    if (isFollowing) {
      await this.feed.unfollowUser(username);
      this.followedUsers.delete(username);
      this.showToast("Unfollowed @" + username, "info");
    } else {
      await this.feed.followUser(username);
      this.followedUsers.add(username);
      this.showToast("Following @" + username, "success");
    }
    
    // Update all follow buttons for this user
    const buttons = document.querySelectorAll("[id='twitter-follow-" + username + "']");
    buttons.forEach((btn: any) => {
      btn.innerText = isFollowing ? "Follow" : "Unfollow";
    });

    // If we just followed, remove any 'Follow Back' buttons for this user
    if (!isFollowing) {
      const followBackBtns = document.querySelectorAll("[id='follow-back-" + username + "']");
      followBackBtns.forEach((btn: any) => btn.remove());
    }
    
    // Update local following count
    if (this.auth.currentUser) {
       const delta = isFollowing ? -1 : 1;
       this.auth.currentUser.followingCount = Math.max(0, (this.auth.currentUser.followingCount || 0) + delta);
       localStorage.setItem('currentUser', JSON.stringify(this.auth.currentUser));
       const followCountEl = document.getElementById('header-following-count');
       if (followCountEl) followCountEl.innerText = this.auth.currentUser.followingCount;
    }

    // Update all follower counts for this user on the screen
    const followerElements = document.querySelectorAll('.tweet-username');
    followerElements.forEach(el => {
      if (el.innerText === '@' + username) {
        const headerTop = el.parentElement;
        const countSpan = headerTop.querySelector('.tweet-followers');
        if (countSpan) {
           const current = parseInt(countSpan.innerText.replace('рҹ‘Ө ', '')) || 0;
           countSpan.innerText = "рҹ‘Ө " + Math.max(0, (isFollowing ? current - 1 : current + 1));
        }
      }
    });
 
    // If on social.html, refresh the list to show updated states and potentially new items
    if (window.location.pathname.includes('social.html') && this.currentSocialUser) {
        await this.renderSocialList('social-list', this.currentSocialUser, this.currentSocialType);
    }

  } catch (e) {
    this.showToast("Action failed: " + e.message, "error");
  }
@@TwitterApp.toggleFollow.end

