@async @Server.start{}: void
@@Server.start.code
  await this.auth.init();

  const server = http.createServer(async (req, res) => {
    // CORS headers just in case we hit it cross-origin, though we assume same-domain right now
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'OPTIONS, POST, GET');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');

    console.log("[BACKEND] " + req.method + " " + req.url);

    if (req.method === 'OPTIONS') {
      res.writeHead(204);
      res.end();
      return;
    }

    // Help verify tokens
    const getAuthUser = (req) => {
      const authHeader = req.headers['authorization'];
      if (!authHeader) return null;
      const token = authHeader.split(' ')[1];
      try {
        return this.auth.verifyToken(token);
      } catch (e) {
        return null;
      }
    };

    if (req.method === 'POST' && req.url === '/api/register') {
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { username, name, pass } = JSON.parse(body);
          const result = await this.auth.register(username, name, pass);
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify(result));
        } catch (e) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/login') {
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { username, pass } = JSON.parse(body);
          const result = await this.auth.login(username, pass);
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify(result));
        } catch (e) {
          res.writeHead(401, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/refresh') {
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { refreshToken } = JSON.parse(body);
          const result = await this.auth.refresh(refreshToken);
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify(result));
        } catch (e) {
          res.writeHead(401, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'GET' && req.url.startsWith('/api/tweets/hashtag')) {
      const url = new URL(req.url, "http://" + req.headers.host);
      const tag = url.searchParams.get('tag');
      const limit = parseInt(url.searchParams.get('limit') || '25');
      const offset = parseInt(url.searchParams.get('offset') || '0');
      if (!tag) {
        res.writeHead(400); res.end(JSON.stringify({ error: "Missing tag" }));
        return;
      }
      try {
        const tweets = await this.auth.db.getMessagesByHashtag(tag, limit, offset);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(tweets));
      } catch (e) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    if (req.method === 'GET' && req.url.startsWith('/api/tweets')) {
      const url = new URL(req.url, "http://" + req.headers.host);
      const limit = parseInt(url.searchParams.get('limit') || '25');
      const offset = parseInt(url.searchParams.get('offset') || '0');
      const username = url.searchParams.get('username');
      const authUser = getAuthUser(req);

      try {
        let tweets;
        if (username) {
          tweets = await this.auth.db.getUserTweets(username, limit, offset);
        } else if (authUser) {
          tweets = await this.auth.db.getPersonalizedTweets(authUser.username, limit, offset);
        } else {
          tweets = await this.auth.db.getPublicTweets(limit, offset);
        }
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(tweets));
      } catch (e) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    if (req.method === 'POST' && req.url === '/api/tweets') {
      const user = getAuthUser(req);
      if (!user) {
        res.writeHead(401);
        res.end(JSON.stringify({ error: "Unauthorized" }));
        return;
      }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { content, repliedToId, retweetedId, imageUrl } = JSON.parse(body);
          const tweet = await this.auth.db.insertMessage(user.username, '', content, Date.now(), repliedToId, retweetedId, imageUrl);
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify(tweet));
        } catch (e) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/upload') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }

      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { base64Data, filename } = JSON.parse(body);

          // Validation: Check data URL prefix for JPG/PNG
          if (!base64Data.startsWith('data:image/jpeg;base64,') && 
              !base64Data.startsWith('data:image/png;base64,')) {
            res.writeHead(400);
            res.end(JSON.stringify({ error: "Only JPG and PNG images are allowed" }));
            return;
          }

          const ext = base64Data.includes('png') ? '.png' : '.jpg';
          const pureBase64 = base64Data.split(',')[1];
          const buffer = Buffer.from(pureBase64, 'base64');

          const newFilename = "upload_" + Date.now() + "_" + Math.floor(Math.random() * 1000) + ext;
          // process.cwd() is src/twitter/server
          const uploadPath = path.join(process.cwd(), 'public', 'images', newFilename);

          if (!fs.existsSync(path.dirname(uploadPath))) {
            fs.mkdirSync(path.dirname(uploadPath), { recursive: true });
          }

          fs.writeFileSync(uploadPath, buffer);

          res.writeHead(200);
          res.end(JSON.stringify({ url: 'http://localhost:8080/images/' + newFilename }));
        } catch (e) {
          res.writeHead(500);
          res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'GET' && req.url.startsWith('/images/')) {
      const fileName = req.url.split('/').pop();
      const imagesDir = path.join(process.cwd(), 'public', 'images');
      const filePath = path.join(imagesDir, fileName);
      if (fs.existsSync(filePath)) {
        const ext = path.extname(filePath).toLowerCase();
        const contentType = ext === '.png' ? 'image/png' : 'image/jpeg';
        res.writeHead(200, { 'Content-Type': contentType });
        fs.createReadStream(filePath).pipe(res);
        return;
      }
    }

    if (req.method === 'GET' && req.url.startsWith('/api/messages')) {
      const user = getAuthUser(req);
      if (!user) {
        res.writeHead(401);
        res.end(JSON.stringify({ error: "Unauthorized" }));
        return;
      }
      const otherUser = new URL(req.url, "http://" + req.headers.host).searchParams.get('with');
      if (!otherUser) {
        res.writeHead(400);
        res.end(JSON.stringify({ error: "Missing 'with' parameter" }));
        return;
      }
      try {
        const messages = await this.auth.db.getMessagesBetween(user.username, otherUser);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(messages));
      } catch (e) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    if (req.method === 'POST' && req.url === '/api/messages') {
      const user = getAuthUser(req);
      if (!user) {
        res.writeHead(401);
        res.end(JSON.stringify({ error: "Unauthorized" }));
        return;
      }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { receiverUsername, content, repliedToId, retweetedId } = JSON.parse(body);
          const msg = await this.auth.db.insertMessage(user.username, receiverUsername, content, Date.now(), repliedToId, retweetedId);
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify(msg));
        } catch (e) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/like') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { messageId } = JSON.parse(body);
          await this.auth.db.likeMessage(messageId, user.username);
          res.writeHead(200); res.end(JSON.stringify({ success: true }));
        } catch (e) {
          console.log(e);
          res.writeHead(400); res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/unlike') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { messageId } = JSON.parse(body);
          await this.auth.db.unlikeMessage(messageId, user.username);
          res.writeHead(200); res.end(JSON.stringify({ success: true }));
        } catch (e) {
          res.writeHead(400); res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/retweet') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { originalId } = JSON.parse(body);
          const retweet = await this.auth.db.retweetMessage(user.username, originalId, Date.now());
          res.writeHead(200); res.end(JSON.stringify(retweet));
        } catch (e) {
          const status = e.message.includes("already retweeted") ? 409 : 400;
          res.writeHead(status); 
          res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/user/avatar') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { avatarUrl } = JSON.parse(body);
          await this.auth.db.updateUserAvatar(user.username, avatarUrl);
          res.writeHead(200); res.end(JSON.stringify({ success: true }));
        } catch (e) {
          res.writeHead(400); res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/user/banner') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { bannerUrl } = JSON.parse(body);
          await this.auth.db.updateUserBanner(user.username, bannerUrl);
          res.writeHead(200); res.end(JSON.stringify({ success: true }));
        } catch (e) {
          res.writeHead(400); res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/follow') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { username } = JSON.parse(body);
          await this.auth.db.followUser(user.username, username);
          res.writeHead(200); res.end(JSON.stringify({ success: true }));
        } catch (e) {
          console.log(e.message);
          res.writeHead(400); res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'POST' && req.url === '/api/unfollow') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      let body = '';
      req.on('data', chunk => { body += chunk; });
      req.on('end', async () => {
        try {
          const { username } = JSON.parse(body);
          await this.auth.db.unfollowUser(user.username, username);
          res.writeHead(200); res.end(JSON.stringify({ success: true }));
        } catch (e) {
          res.writeHead(400); res.end(JSON.stringify({ error: e.message }));
        }
      });
      return;
    }

    if (req.method === 'GET' && req.url.startsWith('/api/following')) {
      const user = getAuthUser(req);
      const url = new URL(req.url, "http://" + req.headers.host);
      const username = url.searchParams.get('username') || (user ? user.username : null);

      if (!username) { res.writeHead(400); res.end(JSON.stringify({ error: "Missing username" })); return; }

      try {
        const following = await this.auth.db.getFollowingDetails(username);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(following));
      } catch (e) {
        res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    if (req.method === 'GET' && req.url.startsWith('/api/followers')) {
       const url = new URL(req.url, "http://" + req.headers.host);
       const username = url.searchParams.get('username');
       if (!username) { res.writeHead(400); res.end(JSON.stringify({ error: "Missing username" })); return; }

       try {
         const followers = await this.auth.db.getFollowersDetails(username);
         res.writeHead(200, { 'Content-Type': 'application/json' });
         res.end(JSON.stringify(followers));
       } catch (e) {
         res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
       }
       return;
    }

    if (req.method === 'GET' && req.url.startsWith('/api/replies')) {
      const tweetId = new URL(req.url, "http://" + req.headers.host).searchParams.get('id');
      if (!tweetId) {
        res.writeHead(400); res.end(JSON.stringify({ error: "Missing 'id' parameter" }));
        return;
      }
      try {
        const replies = await this.auth.db.getReplies(tweetId);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(replies));
      } catch (e) {
        res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    if (req.method === 'GET' && req.url.startsWith('/api/user')) {
      const url = new URL(req.url, "http://" + req.headers.host);
      const username = url.searchParams.get('username');
      if (!username) {
        res.writeHead(400); res.end(JSON.stringify({ error: "Missing username" }));
        return;
      }
      try {
        const user = await this.auth.db.getUser(username);
        if (!user) {
          res.writeHead(404); res.end(JSON.stringify({ error: "User not found" }));
          return;
        }
        // Don't send password hash
        const { password_hash, ...safeUser } = user;
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(safeUser));
      } catch (e) {
        res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    if (req.method === 'GET' && req.url === '/api/trending') {
      try {
        const last24Hours = Date.now() - (24 * 60 * 60 * 1000);
        const trending = await this.auth.db.getTrendingHashtags(last24Hours, 10);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(trending));
      } catch (e) {
        res.writeHead(500);
        res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    if (req.method === 'GET' && req.url.startsWith('/api/notifications')) {
      const url = new URL(req.url, "http://" + req.headers.host);
      const limit = parseInt(url.searchParams.get('limit') || '25');
      const offset = parseInt(url.searchParams.get('offset') || '0');
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      try {
        const notes = await this.auth.db.getNotifications(user.username, limit, offset);
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(notes));
      } catch (e) {
        res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    if (req.method === 'POST' && req.url === '/api/notifications/read') {
      const user = getAuthUser(req);
      if (!user) { res.writeHead(401); res.end(); return; }
      try {
        await this.auth.db.markNotificationsRead(user.username);
        res.writeHead(200); res.end(JSON.stringify({ success: true }));
      } catch (e) {
        res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
      }
      return;
    }

    // Default fallback
    res.writeHead(404);
    res.end();
  });

  server.listen(this.port, () => {
    console.log("[BACKEND] Validating on port " + this.port);
  });
@@Server.start.end

